import { clamp } from '@/shared/lib/math';
import { computeCoverCrop } from '@/shared/lib/image-cache';
import type { CropCustomSize, CropRect, ImageSize, ImageTransform } from '@/shared/types/editor';

export function aspectToRatio(preset: string): number | null {
  const map: Record<string, number> = {
    '1:1': 1,
    '4:3': 4 / 3,
    '16:9': 16 / 9,
    '3:4': 3 / 4,
  };
  return map[preset] ?? null;
}

/** 解析 "600x340" / "600×340" / "600 340" */
export function parseCustomSize(input: string): CropCustomSize | null {
  const normalized = input.trim().replace(/×/g, 'x').replace(/\s+/g, 'x');
  const match = normalized.match(/^(\d{1,5})x(\d{1,5})$/i);
  if (!match) return null;
  const width = Number(match[1]);
  const height = Number(match[2]);
  if (width < 1 || height < 1 || width > 20000 || height > 20000) return null;
  return { width, height };
}

export interface CustomCropSource {
  sx: number;
  sy: number;
  sw: number;
  sh: number;
  outW: number;
  outH: number;
  anchor: 'height' | 'width';
}

/**
 * 自定义比例裁剪（原图像素坐标）：
 * - 高度 > 宽度：以高度为准，等比缩放到目标高度后裁宽度
 * - 宽度 >= 高度：以宽度为准，等比缩放到目标宽度后裁高度
 * - 若主维度缩放后另一维度不足，则切换为另一维度为准（反之亦然）
 */
export function computeCustomRatioCropSource(
  imgW: number,
  imgH: number,
  targetW: number,
  targetH: number,
): CustomCropSource {
  if (imgH > imgW) {
    const scale = targetH / imgH;
    const scaledW = imgW * scale;
    if (scaledW >= targetW) {
      const sw = targetW / scale;
      return {
        sx: (imgW - sw) / 2,
        sy: 0,
        sw,
        sh: imgH,
        outW: targetW,
        outH: targetH,
        anchor: 'height',
      };
    }
    const scaleW = targetW / imgW;
    const sh = targetH / scaleW;
    return {
      sx: 0,
      sy: (imgH - sh) / 2,
      sw: imgW,
      sh,
      outW: targetW,
      outH: targetH,
      anchor: 'width',
    };
  }

  const scale = targetW / imgW;
  const scaledH = imgH * scale;
  if (scaledH >= targetH) {
    const sh = targetH / scale;
    return {
      sx: 0,
      sy: (imgH - sh) / 2,
      sw: imgW,
      sh,
      outW: targetW,
      outH: targetH,
      anchor: 'width',
    };
  }
  const scaleH = targetH / imgH;
  const sw = targetW / scaleH;
  return {
    sx: (imgW - sw) / 2,
    sy: 0,
    sw,
    sh: imgH,
    outW: targetW,
    outH: targetH,
    anchor: 'height',
  };
}

/** 将原图裁剪区域映射到舞台坐标 */
export function customCropSourceToStageRect(
  src: CustomCropSource,
  transform: ImageTransform,
): CropRect {
  return {
    x: transform.x + src.sx * transform.scale,
    y: transform.y + src.sy * transform.scale,
    width: src.sw * transform.scale,
    height: src.sh * transform.scale,
  };
}

/** 按图片长边等比缩放后居中裁剪到目标宽高比 */
export function computeCropRectForAspect(
  imgSize: ImageSize,
  _stageSize: ImageSize,
  aspectRatio: number,
  transform: ImageTransform,
): CropRect {
  const displayW = imgSize.width * transform.scale;
  const displayH = imgSize.height * transform.scale;
  const originX = transform.x;
  const originY = transform.y;

  let cropW: number;
  let cropH: number;
  if (displayW / displayH > aspectRatio) {
    cropH = displayH;
    cropW = cropH * aspectRatio;
  } else {
    cropW = displayW;
    cropH = cropW / aspectRatio;
  }

  return {
    x: originX + (displayW - cropW) / 2,
    y: originY + (displayH - cropH) / 2,
    width: cropW,
    height: cropH,
  };
}

export function computeCropRectForCustomSize(
  imgSize: ImageSize,
  custom: CropCustomSize,
  transform: ImageTransform,
): CropRect {
  const src = computeCustomRatioCropSource(imgSize.width, imgSize.height, custom.width, custom.height);
  return customCropSourceToStageRect(src, transform);
}

export function stageRectToImageRect(
  crop: CropRect,
  imgSize: ImageSize,
  transform: ImageTransform,
): CropRect {
  const sx = clamp((crop.x - transform.x) / transform.scale, 0, imgSize.width);
  const sy = clamp((crop.y - transform.y) / transform.scale, 0, imgSize.height);
  const sw = clamp(crop.width / transform.scale, 1, imgSize.width - sx);
  const sh = clamp(crop.height / transform.scale, 1, imgSize.height - sy);
  return { x: sx, y: sy, width: sw, height: sh };
}

export async function loadImageElement(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });
}

/** 执行裁剪并返回新图片 dataURL */
export async function applyCrop(
  imageSrc: string,
  cropRect: CropRect,
  imgSize: ImageSize,
  transform: ImageTransform,
): Promise<{ dataUrl: string; width: number; height: number }> {
  const img = await loadImageElement(imageSrc);
  const src = stageRectToImageRect(cropRect, imgSize, transform);

  const canvas = document.createElement('canvas');
  canvas.width = Math.round(src.width);
  canvas.height = Math.round(src.height);
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Canvas 2D unavailable');

  ctx.drawImage(img, src.x, src.y, src.width, src.height, 0, 0, canvas.width, canvas.height);
  return { dataUrl: canvas.toDataURL('image/png'), width: canvas.width, height: canvas.height };
}

/** 按自定义宽高算法裁剪，输出精确 targetW × targetH */
export async function cropToCustomRatio(
  imageSrc: string,
  targetW: number,
  targetH: number,
): Promise<{ dataUrl: string; width: number; height: number; anchor: 'height' | 'width' }> {
  const img = await loadImageElement(imageSrc);
  const { sx, sy, sw, sh, outW, outH, anchor } = computeCustomRatioCropSource(
    img.naturalWidth,
    img.naturalHeight,
    targetW,
    targetH,
  );
  const canvas = document.createElement('canvas');
  canvas.width = outW;
  canvas.height = outH;
  const ctx = canvas.getContext('2d')!;
  ctx.drawImage(img, sx, sy, sw, sh, 0, 0, outW, outH);
  return { dataUrl: canvas.toDataURL('image/png'), width: outW, height: outH, anchor };
}

/** cover 算法：按 max(w,h) 等比缩放后裁到目标尺寸 */
export function coverCropSource(
  imgW: number,
  imgH: number,
  targetW: number,
  targetH: number,
): CropRect {
  const { sx, sy, sw, sh } = computeCoverCrop(imgW, imgH, targetW, targetH);
  return { x: sx, y: sy, width: sw, height: sh };
}

export async function cropToTargetSize(
  imageSrc: string,
  targetW: number,
  targetH: number,
): Promise<{ dataUrl: string; width: number; height: number }> {
  const img = await loadImageElement(imageSrc);
  const { sx, sy, sw, sh } = computeCoverCrop(img.naturalWidth, img.naturalHeight, targetW, targetH);
  const canvas = document.createElement('canvas');
  canvas.width = targetW;
  canvas.height = targetH;
  const ctx = canvas.getContext('2d')!;
  ctx.drawImage(img, sx, sy, sw, sh, 0, 0, targetW, targetH);
  return { dataUrl: canvas.toDataURL('image/png'), width: targetW, height: targetH };
}
