import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { ImageUploadButton } from '@/features/import/ui/image-upload';
import { haptic } from '@/shared/lib/haptic';
import { ToolIcon } from '@/shared/ui/tool-icon';

export function TopBar() {
  const canUndo = useHistoryStore((s) => s.past.length > 0);
  const canRedo = useHistoryStore((s) => s.future.length > 0);
  const undo = useHistoryStore((s) => s.undo);
  const redo = useHistoryStore((s) => s.redo);
  const openSheet = useEditorStore((s) => s.openSheet);

  return (
    <header className="top-bar glass" data-testid="top-bar">
      <div className="top-bar__left">
        <button
          type="button"
          className="icon-btn"
          aria-label="关闭"
          onClick={() => {
            haptic('light');
            window.history.back();
          }}
        >
          <ToolIcon name="close" />
        </button>
        <ImageUploadButton />
      </div>

      <div className="top-bar__actions">
        <button
          type="button"
          className="icon-btn"
          aria-label="撤销"
          disabled={!canUndo}
          onClick={() => {
            haptic('light');
            undo();
          }}
        >
          <ToolIcon name="undo" />
        </button>
        <button
          type="button"
          className="icon-btn"
          aria-label="重做"
          disabled={!canRedo}
          onClick={() => {
            haptic('light');
            redo();
          }}
        >
          <ToolIcon name="redo" />
        </button>
      </div>

      <button
        type="button"
        className="btn-accent"
        onClick={() => {
          haptic('medium');
          openSheet('export');
        }}
      >
        完成
      </button>
    </header>
  );
}
