import type { GuideLine, Point } from '@/shared/types/editor';

const SNAP_THRESHOLD = 8;

export interface SnapTarget {
  x?: number;
  y?: number;
}

export function computeSnap(
  pos: Point,
  nodeSize: { width: number; height: number },
  stageSize: { width: number; height: number },
  otherBounds: Array<{ x: number; y: number; width: number; height: number }>,
  enabled: boolean,
): { x: number; y: number; guides: GuideLine[] } {
  if (!enabled) return { x: pos.x, y: pos.y, guides: [] };

  const guides: GuideLine[] = [];
  let x = pos.x;
  let y = pos.y;

  const cx = x + nodeSize.width / 2;
  const cy = y + nodeSize.height / 2;
  const stageCx = stageSize.width / 2;
  const stageCy = stageSize.height / 2;

  const xTargets = [0, stageCx - nodeSize.width / 2, stageSize.width - nodeSize.width, stageCx - nodeSize.width / 2];
  const yTargets = [0, stageCy - nodeSize.height / 2, stageSize.height - nodeSize.height, stageCy - nodeSize.height / 2];

  for (const ob of otherBounds) {
    xTargets.push(ob.x, ob.x + ob.width / 2 - nodeSize.width / 2, ob.x + ob.width - nodeSize.width);
    yTargets.push(ob.y, ob.y + ob.height / 2 - nodeSize.height / 2, ob.y + ob.height - nodeSize.height);
  }

  for (const tx of xTargets) {
    if (Math.abs(x - tx) < SNAP_THRESHOLD) {
      x = tx;
      guides.push({ id: `v-${tx}`, orientation: 'v', position: tx + nodeSize.width / 2 });
      break;
    }
    if (Math.abs(cx - (tx + nodeSize.width / 2)) < SNAP_THRESHOLD) {
      x = tx;
      guides.push({ id: `vc-${tx}`, orientation: 'v', position: tx + nodeSize.width / 2 });
      break;
    }
  }

  for (const ty of yTargets) {
    if (Math.abs(y - ty) < SNAP_THRESHOLD) {
      y = ty;
      guides.push({ id: `h-${ty}`, orientation: 'h', position: ty + nodeSize.height / 2 });
      break;
    }
    if (Math.abs(cy - (ty + nodeSize.height / 2)) < SNAP_THRESHOLD) {
      y = ty;
      guides.push({ id: `hc-${ty}`, orientation: 'h', position: ty + nodeSize.height / 2 });
      break;
    }
  }

  if (Math.abs(cx - stageCx) < SNAP_THRESHOLD) {
    x = stageCx - nodeSize.width / 2;
    guides.push({ id: 'vc-center', orientation: 'v', position: stageCx });
  }
  if (Math.abs(cy - stageCy) < SNAP_THRESHOLD) {
    y = stageCy - nodeSize.height / 2;
    guides.push({ id: 'hc-center', orientation: 'h', position: stageCy });
  }

  return { x, y, guides };
}

export function snapRotation(angle: number, enabled: boolean): number {
  if (!enabled) return angle;
  const snaps = [0, 45, 90, 135, 180, 225, 270, 315];
  for (const s of snaps) {
    if (Math.abs(angle - s) < 5) return s;
  }
  return angle;
}
