import { useEffect, useRef } from 'react';
import { Group, Rect, Line, Transformer } from 'react-konva';
import type Konva from 'konva';
import { useEditorStore } from '@/entities/editor/model/editor-store';

export function GuideLinesLayer() {
  const guideLines = useEditorStore((s) => s.guideLines);
  const stageW = useRef(375);
  const stageH = useRef(667);

  useEffect(() => {
    const update = () => {
      const canvas = document.querySelector('.editor-canvas');
      if (canvas) {
        stageW.current = canvas.clientWidth;
        stageH.current = canvas.clientHeight;
      }
    };
    update();
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);

  return (
    <>
      {guideLines.map((g) =>
        g.orientation === 'v' ? (
          <Line
            key={g.id}
            points={[g.position, 0, g.position, stageH.current]}
            stroke="#FF4D4F"
            strokeWidth={1}
            dash={[4, 4]}
            listening={false}
          />
        ) : (
          <Line
            key={g.id}
            points={[0, g.position, stageW.current, g.position]}
            stroke="#FF4D4F"
            strokeWidth={1}
            dash={[4, 4]}
            listening={false}
          />
        ),
      )}
    </>
  );
}

interface CropOverlayProps {
  cropTransformerRef: React.RefObject<Konva.Transformer | null>;
}

function CropDimOverlay({ crop }: { crop: { x: number; y: number; width: number; height: number } }) {
  const sw = 9999;
  const sh = 9999;
  const { x, y, width, height } = crop;
  const dim = 'rgba(0,0,0,0.55)';
  return (
    <>
      <Rect x={0} y={0} width={sw} height={y} fill={dim} listening={false} />
      <Rect x={0} y={y + height} width={sw} height={sh} fill={dim} listening={false} />
      <Rect x={0} y={y} width={x} height={height} fill={dim} listening={false} />
      <Rect x={x + width} y={y} width={sw} height={height} fill={dim} listening={false} />
    </>
  );
}

export function CropOverlay({ cropTransformerRef }: CropOverlayProps) {
  const activeTool = useEditorStore((s) => s.activeTool);
  const cropRect = useEditorStore((s) => s.cropRect);
  const setCropRect = useEditorStore((s) => s.setCropRect);
  const cropRectRef = useRef<Konva.Rect>(null);

  useEffect(() => {
    const tr = cropTransformerRef.current;
    const node = cropRectRef.current;
    if (tr && node && activeTool === 'crop') {
      tr.nodes([node]);
      tr.getLayer()?.batchDraw();
    } else if (tr) {
      tr.nodes([]);
    }
  }, [activeTool, cropRect, cropTransformerRef]);

  if (activeTool !== 'crop' || !cropRect) return null;

  return (
    <Group name="crop-overlay">
      <CropDimOverlay crop={cropRect} />
      <Rect
        ref={cropRectRef}
        id="crop-rect"
        x={cropRect.x}
        y={cropRect.y}
        width={cropRect.width}
        height={cropRect.height}
        fill="transparent"
        stroke="#4F8CFF"
        strokeWidth={2}
        dash={[8, 4]}
        draggable
        onDragEnd={(e) => {
          setCropRect({
            x: e.target.x(),
            y: e.target.y(),
            width: cropRect.width,
            height: cropRect.height,
          });
        }}
        onTransformEnd={(e) => {
          const node = e.target;
          const scaleX = node.scaleX();
          const scaleY = node.scaleY();
          node.scaleX(1);
          node.scaleY(1);
          setCropRect({
            x: node.x(),
            y: node.y(),
            width: Math.max(20, node.width() * scaleX),
            height: Math.max(20, node.height() * scaleY),
          });
        }}
      />
    </Group>
  );
}

export function CropTransformer({ cropTransformerRef }: CropOverlayProps) {
  const activeTool = useEditorStore((s) => s.activeTool);
  const cropAspect = useEditorStore((s) => s.cropAspect);
  if (activeTool !== 'crop') return null;
  return (
    <Transformer
      ref={cropTransformerRef}
      rotateEnabled={false}
      keepRatio={cropAspect !== 'free'}
      enabledAnchors={['top-left', 'top-right', 'bottom-left', 'bottom-right', 'middle-left', 'middle-right', 'top-center', 'bottom-center']}
      borderStroke="#4F8CFF"
      anchorStroke="#4F8CFF"
      anchorFill="#FFFFFF"
      boundBoxFunc={(oldBox, newBox) => {
        if (newBox.width < 20 || newBox.height < 20) return oldBox;
        return newBox;
      }}
    />
  );
}
