import { useEffect, useRef, useCallback } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { haptic } from '@/shared/lib/haptic';

const LENS_SIZE = 120;

export function MagnifierLens() {
  const activeTool = useEditorStore((s) => s.activeTool);
  const magnifierZoom = useEditorStore((s) => s.magnifierZoom);
  const magnifierPosition = useEditorStore((s) => s.magnifierPosition);
  const setMagnifierZoom = useEditorStore((s) => s.setMagnifierZoom);
  const setMagnifierPosition = useEditorStore((s) => s.setMagnifierPosition);
  const lensCanvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);

  const drawLens = useCallback(() => {
    const pos = magnifierPosition;
    const lensCanvas = lensCanvasRef.current;
    const sourceCanvas = document.querySelector('.editor-canvas canvas') as HTMLCanvasElement | null;
    if (!pos || !lensCanvas || !sourceCanvas) return;

    const ctx = lensCanvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const srcSize = LENS_SIZE / magnifierZoom;
    const sx = pos.x * dpr - (srcSize * dpr) / 2;
    const sy = pos.y * dpr - (srcSize * dpr) / 2;

    ctx.clearRect(0, 0, LENS_SIZE, LENS_SIZE);
    ctx.save();
    ctx.beginPath();
    ctx.arc(LENS_SIZE / 2, LENS_SIZE / 2, LENS_SIZE / 2 - 2, 0, Math.PI * 2);
    ctx.clip();
    ctx.drawImage(sourceCanvas, sx, sy, srcSize * dpr, srcSize * dpr, 0, 0, LENS_SIZE, LENS_SIZE);
    ctx.restore();
    ctx.strokeStyle = '#4F8CFF';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(LENS_SIZE / 2, LENS_SIZE / 2, LENS_SIZE / 2 - 2, 0, Math.PI * 2);
    ctx.stroke();
  }, [magnifierPosition, magnifierZoom]);

  useEffect(() => {
    if (activeTool !== 'magnifier') return;
    cancelAnimationFrame(rafRef.current);
    rafRef.current = requestAnimationFrame(drawLens);
  }, [activeTool, drawLens, magnifierPosition, magnifierZoom]);

  useEffect(() => {
    if (activeTool !== 'magnifier') return;

    const handleMove = (e: MouseEvent | TouchEvent) => {
      const canvas = document.querySelector('.editor-canvas');
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      let clientX: number;
      let clientY: number;
      if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
      } else {
        clientX = e.clientX;
        clientY = e.clientY;
      }
      setMagnifierPosition({ x: clientX - rect.left, y: clientY - rect.top });
    };

    window.addEventListener('mousemove', handleMove, { passive: true });
    window.addEventListener('touchmove', handleMove, { passive: true });
    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('touchmove', handleMove);
    };
  }, [activeTool, setMagnifierPosition]);

  if (activeTool !== 'magnifier') return null;

  const left = magnifierPosition ? magnifierPosition.x - LENS_SIZE / 2 : 0;
  const top = magnifierPosition ? magnifierPosition.y - LENS_SIZE - 20 : 0;

  return (
    <>
      <div
        className="magnifier-lens"
        data-testid="magnifier-lens"
        style={{
          left: Math.max(8, Math.min(left, window.innerWidth - LENS_SIZE - 8)),
          top: Math.max(60, top),
        }}
      >
        <canvas ref={lensCanvasRef} width={LENS_SIZE} height={LENS_SIZE} />
        <span className="magnifier-lens__zoom">{magnifierZoom.toFixed(1)}x</span>
      </div>
      <div className="tool-overlay glass magnifier-controls" data-testid="magnifier-controls">
        <label htmlFor="magnifier-zoom">
          放大倍数
          <input
            id="magnifier-zoom"
            type="range"
            min={1.5}
            max={5}
            step={0.1}
            value={magnifierZoom}
            onChange={(e) => {
              haptic('light');
              setMagnifierZoom(Number(e.target.value));
            }}
          />
        </label>
      </div>
    </>
  );
}
