import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { PRIMARY_TOOLS, TOOLS } from '@/shared/config/tools';
import { haptic } from '@/shared/lib/haptic';
import type { ToolId } from '@/shared/types/editor';
import { ToolIcon } from '@/shared/ui/tool-icon';

const PRIMARY_LABELS: Record<string, string> = {
  select: '选择',
  pen: '画笔',
  rectangle: '形状',
  text: '文字',
  mosaic: '马赛克',
  more: '更多',
};

export function FloatingToolbar() {
  const toolbarVisible = useEditorStore((s) => s.toolbarVisible);
  const activeTool = useEditorStore((s) => s.activeTool);
  const setActiveTool = useEditorStore((s) => s.setActiveTool);

  if (!toolbarVisible) return null;

  return (
    <nav className="floating-toolbar glass" data-testid="floating-toolbar" aria-label="工具栏">
      <div className="floating-toolbar__scroll">
        {PRIMARY_TOOLS.map((toolId) => {
          const tool = TOOLS.find((t) => t.id === toolId);
          if (!tool) return null;
          const isActive = activeTool === toolId || (toolId === 'rectangle' && ['rectangle', 'circle', 'arrow', 'line'].includes(activeTool));
          return (
            <button
              key={toolId}
              type="button"
              className={`tool-btn ${isActive ? 'tool-btn--active' : ''}`}
              onClick={() => {
                haptic('light');
                setActiveTool(toolId as ToolId);
              }}
              aria-label={PRIMARY_LABELS[toolId] ?? tool.label}
              aria-pressed={isActive}
            >
              <ToolIcon name={tool.icon} />
              <span>{PRIMARY_LABELS[toolId] ?? tool.label}</span>
            </button>
          );
        })}
      </div>
    </nav>
  );
}

export function SelectionToolbar() {
  const selectedIds = useEditorStore((s) => s.selectedIds);
  const removeObject = useEditorStore((s) => s.removeObject);
  const duplicateSelected = useEditorStore((s) => s.duplicateSelected);
  const pushHistory = useHistoryStore((s) => s.pushHistory);

  if (selectedIds.length === 0) return null;

  return (
    <div className="selection-toolbar glass" data-testid="selection-toolbar">
      <button
        type="button"
        className="icon-btn icon-btn--danger"
        aria-label="删除"
        onClick={() => {
          haptic('medium');
          selectedIds.forEach((id) => removeObject(id));
          pushHistory('delete');
        }}
      >
        <ToolIcon name="delete" />
      </button>
      <button
        type="button"
        className="icon-btn"
        aria-label="复制"
        onClick={() => {
          haptic('light');
          duplicateSelected();
          pushHistory('duplicate');
        }}
      >
        <ToolIcon name="copy" />
      </button>
      <button type="button" className="icon-btn" aria-label="锁定">
        <ToolIcon name="lock" />
      </button>
      <button type="button" className="icon-btn" aria-label="旋转">
        <ToolIcon name="rotate" />
      </button>
      <button type="button" className="icon-btn" aria-label="翻转">
        <ToolIcon name="flip" />
      </button>
    </div>
  );
}
