import { motion } from '@/shared/config/theme';

export function spring(value: number, target: number, velocity: number, stiffness = 0.15, damping = 0.8): [number, number] {
  const force = (target - value) * stiffness;
  const newVelocity = (velocity + force) * damping;
  return [value + newVelocity, newVelocity];
}

export const cssTransition = (props = 'all') =>
  `${props} ${motion.duration}ms ${motion.ease}`;

export function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

export function distance(a: { x: number; y: number }, b: { x: number; y: number }): number {
  return Math.hypot(b.x - a.x, b.y - a.y);
}

export function angleBetween(a: { x: number; y: number }, b: { x: number; y: number }, c: { x: number; y: number }): number {
  const ab = distance(a, b);
  const bc = distance(b, c);
  const ac = distance(a, c);
  if (ab === 0 || bc === 0) return 0;
  const cos = clamp((ab ** 2 + bc ** 2 - ac ** 2) / (2 * ab * bc), -1, 1);
  return (Math.acos(cos) * 180) / Math.PI;
}

export function polygonArea(points: { x: number; y: number }[]): number {
  let area = 0;
  for (let i = 0; i < points.length; i++) {
    const j = (i + 1) % points.length;
    area += points[i].x * points[j].y;
    area -= points[j].x * points[i].y;
  }
  return Math.abs(area / 2);
}
