import { generatePrivacyPatch } from '@/features/privacy/model/privacy-filter';
import type { PrivacyMode } from '@/features/privacy/model/privacy-filter';
import { useEditorStore } from '@/entities/editor/model/editor-store';

export async function finalizePrivacyPatch(objectId: string, mode: PrivacyMode): Promise<boolean> {
  const store = useEditorStore.getState();
  const obj = store.objects.find((o) => o.id === objectId);
  if (!obj || !store.imageSrc || !store.imageNaturalSize) {
    store.removeObject(objectId);
    return false;
  }

  const stageRect = {
    x: obj.attrs.x as number,
    y: obj.attrs.y as number,
    width: obj.attrs.width as number,
    height: obj.attrs.height as number,
  };

  if (stageRect.width < 6 || stageRect.height < 6) {
    store.removeObject(objectId);
    return false;
  }

  try {
    const patchSrc = await generatePrivacyPatch({
      imageSrc: store.imageSrc,
      imageNaturalSize: store.imageNaturalSize,
      imageTransform: store.imageTransform,
      stageRect,
      mode,
    });

    store.removeObject(objectId);
    store.addObject({
      layerId: 'layer-sticker',
      type: 'privacy-patch',
      attrs: {
        x: stageRect.x,
        y: stageRect.y,
        width: stageRect.width,
        height: stageRect.height,
        patchSrc,
        mode,
      },
    });
    return true;
  } catch {
    store.removeObject(objectId);
    return false;
  }
}
