import { useEditorStore } from '@/entities/editor/model/editor-store';
import { downloadBlob, exportEditor } from '@/features/export/model/export-service';
import { haptic } from '@/shared/lib/haptic';
import type { ExportOptions } from '@/shared/types/editor';

export function ExportPanel() {
  const closeSheet = useEditorStore((s) => s.closeSheet);
  const imageSrc = useEditorStore((s) => s.imageSrc);
  const imageNaturalSize = useEditorStore((s) => s.imageNaturalSize);
  const imageTransform = useEditorStore((s) => s.imageTransform);
  const objects = useEditorStore((s) => s.objects);
  const layers = useEditorStore((s) => s.layers);

  const handleExport = async (format: ExportOptions['format']) => {
    haptic('medium');
    if (!imageSrc || !imageNaturalSize) {
      alert('请先上传图片');
      return;
    }

    const { blob, width, height } = await exportEditor(
      { imageSrc, imageNaturalSize, imageTransform, objects, layers },
      { format, quality: 0.92, pixelRatio: 1 },
    );

    const ext = format === 'jpeg' ? 'jpg' : format;
    downloadBlob(blob, `imgo-${width}x${height}.${ext}`);
    closeSheet();
  };

  const sizeLabel = imageNaturalSize
    ? `${imageNaturalSize.width} × ${imageNaturalSize.height} px`
    : '—';

  return (
    <div className="export-panel" data-testid="export-panel">
      <h3>导出格式</h3>
      <p className="export-panel__hint">按图片真实像素导出（非屏幕截图）</p>
      <p className="export-panel__size" data-testid="export-size">
        当前尺寸：<strong>{sizeLabel}</strong>
      </p>
      <div className="export-panel__formats">
        {(['png', 'jpeg', 'webp', 'pdf'] as const).map((fmt) => (
          <button key={fmt} type="button" className="btn-accent btn-accent--outline" onClick={() => handleExport(fmt)}>
            {fmt.toUpperCase()}
          </button>
        ))}
      </div>
    </div>
  );
}
