import { create } from 'zustand';
import { immer } from 'zustand/middleware/immer';
import type { HistoryEntry } from '@/shared/types/editor';
import { nextId, useEditorStore } from '@/entities/editor/model/editor-store';

interface HistoryState {
  past: HistoryEntry[];
  future: HistoryEntry[];
  maxSteps: number;
}

interface HistoryActions {
  pushHistory: (label: string) => void;
  undo: () => void;
  redo: () => void;
  canUndo: () => boolean;
  canRedo: () => boolean;
  clear: () => void;
}

const takeSnapshot = (): HistoryEntry['snapshot'] => {
  const { objects, layers, imageTransform } = useEditorStore.getState();
  return {
    objects: objects.map((o) => ({ ...o, attrs: { ...o.attrs } })),
    layers: layers.map((l) => ({ ...l, nodeIds: [...l.nodeIds] })),
    imageTransform: { ...imageTransform },
  };
};

export const useHistoryStore = create<HistoryState & HistoryActions>()(
  immer((set, get) => ({
    past: [],
    future: [],
    maxSteps: 200,

    pushHistory: (label) => {
      const entry: HistoryEntry = {
        id: nextId('hist'),
        timestamp: Date.now(),
        label,
        snapshot: takeSnapshot(),
      };
      set((s) => {
        s.past.push(entry);
        if (s.past.length > s.maxSteps) s.past.shift();
        s.future = [];
      });
    },

    undo: () => {
      const { past } = get();
      if (past.length === 0) return;
      const current = takeSnapshot();
      const entry = past[past.length - 1];
      set((s) => {
        s.past.pop();
        s.future.unshift({
          id: nextId('hist'),
          timestamp: Date.now(),
          label: 'redo-point',
          snapshot: current,
        });
      });
      useEditorStore.getState().loadSnapshot(
        entry.snapshot.objects,
        entry.snapshot.layers,
        entry.snapshot.imageTransform,
      );
    },

    redo: () => {
      const { future } = get();
      if (future.length === 0) return;
      const current = takeSnapshot();
      const entry = future[0];
      set((s) => {
        s.future.shift();
        s.past.push({
          id: nextId('hist'),
          timestamp: Date.now(),
          label: 'undo-point',
          snapshot: current,
        });
      });
      useEditorStore.getState().loadSnapshot(
        entry.snapshot.objects,
        entry.snapshot.layers,
        entry.snapshot.imageTransform,
      );
    },

    canUndo: () => get().past.length > 0,
    canRedo: () => get().future.length > 0,

    clear: () =>
      set((s) => {
        s.past = [];
        s.future = [];
      }),
  })),
);
