import { useState } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { recognizeText } from '@/features/ocr/model/ocr-service';
import { haptic } from '@/shared/lib/haptic';

export function OcrPanel() {
  const ocrBlocks = useEditorStore((s) => s.ocrBlocks);
  const setOcrBlocks = useEditorStore((s) => s.setOcrBlocks);
  const [loading, setLoading] = useState(false);

  const runOcr = async () => {
    haptic('medium');
    setLoading(true);
    try {
      const canvas = document.querySelector('.editor-canvas canvas') as HTMLCanvasElement | null;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const blocks = await recognizeText(imageData);
      setOcrBlocks(blocks);
    } finally {
      setLoading(false);
    }
  };

  const copyText = (text: string) => {
    haptic('light');
    navigator.clipboard?.writeText(text);
  };

  return (
    <div className="ocr-panel" data-testid="ocr-panel">
      <button type="button" className="btn-accent" onClick={runOcr} disabled={loading}>
        {loading ? '识别中…' : '开始 OCR 识别'}
      </button>

      {ocrBlocks.length > 0 && (
        <div className="ocr-results">
          <h3>识别结果</h3>
          {ocrBlocks.map((block) => (
            <div key={block.id} className="ocr-block">
              <p>{block.text}</p>
              <div className="ocr-block__actions">
                <button type="button" onClick={() => copyText(block.text)}>
                  复制
                </button>
                <button type="button">编辑</button>
              </div>
              <span className="ocr-block__confidence">{Math.round(block.confidence * 100)}%</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
