import Konva from 'konva';
import type { EditorLayer, EditorObject, ExportOptions, ImageSize, ImageTransform } from '@/shared/types/editor';
import { loadImageElement } from '@/features/crop/model/crop-service';
import { mapAttrsToImageSpace } from '@/features/export/model/export-map';

export interface ExportContext {
  imageSrc: string;
  imageNaturalSize: ImageSize;
  imageTransform: ImageTransform;
  objects: EditorObject[];
  layers: EditorLayer[];
}

function isLayerVisible(obj: EditorObject, layers: EditorLayer[]): boolean {
  const layer = layers.find((l) => l.id === obj.layerId);
  return layer?.visible !== false && obj.visible !== false;
}

async function addShapeToLayer(
  layer: Konva.Layer,
  obj: EditorObject,
  attrs: Record<string, unknown>,
  opacity: number,
): Promise<void> {
  const common = { ...attrs, opacity, listening: false };

  switch (obj.type) {
    case 'arrow':
      layer.add(new Konva.Arrow(common as Konva.ArrowConfig));
      break;
    case 'line':
    case 'measure':
      layer.add(new Konva.Line(common as Konva.LineConfig));
      break;
    case 'privacy-patch': {
      const patchSrc = obj.attrs.patchSrc as string | undefined;
      if (patchSrc) {
        const patchImg = await loadImageElement(patchSrc);
        layer.add(
          new Konva.Image({
            x: attrs.x as number,
            y: attrs.y as number,
            width: attrs.width as number,
            height: attrs.height as number,
            image: patchImg,
            opacity,
            listening: false,
          }),
        );
      }
      break;
    }
    case 'rect':
    case 'rectangle':
    case 'privacy-preview':
      layer.add(new Konva.Rect(common as Konva.RectConfig));
      break;
    case 'circle':
      layer.add(new Konva.Circle(common as Konva.CircleConfig));
      break;
    case 'ellipse':
      layer.add(new Konva.Ellipse(common as Konva.EllipseConfig));
      break;
    case 'text':
    case 'watermark':
      layer.add(new Konva.Text(common as Konva.TextConfig));
      break;
    case 'label': {
      const label = new Konva.Label({ x: attrs.x as number, y: attrs.y as number, opacity });
      label.add(new Konva.Tag({ fill: (attrs.fillShape as string) ?? '#4F8CFF', cornerRadius: 12 }));
      label.add(new Konva.Text({ text: attrs.text as string, fill: '#fff', padding: 8, fontSize: 18 }));
      layer.add(label);
      break;
    }
    default:
      break;
  }
}

/** 按图片真实像素尺寸导出（含标注层），pixelRatio 固定为 1 */
export async function exportEditorComposition(
  ctx: ExportContext,
  options: ExportOptions,
): Promise<{ blob: Blob; width: number; height: number }> {
  const { imageSrc, imageNaturalSize, imageTransform, objects, layers } = ctx;
  const w = imageNaturalSize.width;
  const h = imageNaturalSize.height;

  const container = document.createElement('div');
  const stage = new Konva.Stage({ container, width: w, height: h });
  const imageLayer = new Konva.Layer();
  const shapeLayer = new Konva.Layer();

  const img = await loadImageElement(imageSrc);
  imageLayer.add(
    new Konva.Image({
      image: img,
      x: 0,
      y: 0,
      width: w,
      height: h,
      listening: false,
    }),
  );

  for (const obj of objects) {
    if (!isLayerVisible(obj, layers)) continue;
    if (obj.type === 'privacy-preview') continue;
    const layerMeta = layers.find((l) => l.id === obj.layerId);
    const attrs = mapAttrsToImageSpace(obj.attrs, imageTransform);
    await addShapeToLayer(shapeLayer, obj, attrs, layerMeta?.opacity ?? 1);
  }

  stage.add(imageLayer);
  stage.add(shapeLayer);
  stage.draw();

  const mimeMap: Record<ExportOptions['format'], string> = {
    png: 'image/png',
    jpeg: 'image/jpeg',
    webp: 'image/webp',
    pdf: 'image/png',
  };

  const mime = options.format === 'pdf' ? 'image/jpeg' : mimeMap[options.format];
  const dataUrl = stage.toDataURL({
    x: 0,
    y: 0,
    width: w,
    height: h,
    pixelRatio: 1,
    mimeType: mime,
    quality: options.quality,
  });

  stage.destroy();
  container.remove();

  if (options.format === 'pdf') {
    const { jsPDF } = await import('jspdf');
    const pdf = new jsPDF({
      orientation: w > h ? 'landscape' : 'portrait',
      unit: 'px',
      format: [w, h],
    });
    pdf.addImage(dataUrl, 'JPEG', 0, 0, w, h);
    const blob = pdf.output('blob');
    return { blob, width: w, height: h };
  }

  const res = await fetch(dataUrl);
  const blob = await res.blob();
  return { blob, width: w, height: h };
}
