const imageCache = new Map<string, ImageBitmap>();

export async function loadImageBitmap(src: string): Promise<ImageBitmap> {
  const cached = imageCache.get(src);
  if (cached) return cached;

  const response = await fetch(src);
  const blob = await response.blob();
  const bitmap = await createImageBitmap(blob);
  imageCache.set(src, bitmap);
  return bitmap;
}

export function releaseImageCache(): void {
  for (const bitmap of imageCache.values()) {
    bitmap.close();
  }
  imageCache.clear();
}

export function getPixelRatio(): number {
  return Math.min(window.devicePixelRatio || 1, 3);
}

/** Crop algorithm: scale by max dimension then crop to target aspect */
export function computeCoverCrop(
  imgW: number,
  imgH: number,
  targetW: number,
  targetH: number,
): { sx: number; sy: number; sw: number; sh: number } {
  const scale = Math.max(targetW / imgW, targetH / imgH);
  const sw = targetW / scale;
  const sh = targetH / scale;
  const sx = (imgW - sw) / 2;
  const sy = (imgH - sh) / 2;
  return { sx, sy, sw, sh };
}
