import { stageRectToImageRect, loadImageElement } from '@/features/crop/model/crop-service';
import type { CropRect, ImageSize, ImageTransform } from '@/shared/types/editor';

/** 马赛克块越大越难恢复，24px 为默认最大档 */
export const MAX_MOSAIC_BLOCK = 24;

/** 模糊缩小比例，越小越模糊（0.04 ≈ 25 倍降采样） */
export const MAX_BLUR_DOWNSCALE = 0.04;

export type PrivacyMode = 'mosaic' | 'blur';

/**
 * 高效马赛克：先缩小（区域平均）再最近邻放大，O(n) 单次 GPU drawImage
 */
export function applyMosaicCanvas(canvas: HTMLCanvasElement, blockSize = MAX_MOSAIC_BLOCK): void {
  const w = canvas.width;
  const h = canvas.height;
  const block = Math.max(8, Math.min(blockSize, Math.floor(Math.min(w, h) / 3)));
  const smallW = Math.max(1, Math.ceil(w / block));
  const smallH = Math.max(1, Math.ceil(h / block));

  const tmp = document.createElement('canvas');
  tmp.width = smallW;
  tmp.height = smallH;
  const tctx = tmp.getContext('2d')!;
  tctx.imageSmoothingEnabled = true;
  tctx.drawImage(canvas, 0, 0, w, h, 0, 0, smallW, smallH);

  const ctx = canvas.getContext('2d')!;
  ctx.imageSmoothingEnabled = false;
  ctx.clearRect(0, 0, w, h);
  ctx.drawImage(tmp, 0, 0, smallW, smallH, 0, 0, w, h);
}

/**
 * 高效强模糊：极端降采样 + 双线性放大，两次 pass 增强抗恢复
 */
export function applyHeavyBlurCanvas(canvas: HTMLCanvasElement, downscale = MAX_BLUR_DOWNSCALE): void {
  const passes = 2;
  let scale = downscale;
  for (let i = 0; i < passes; i++) {
    downscalePass(canvas, scale);
    scale = Math.min(0.5, scale * 4);
  }
}

function downscalePass(canvas: HTMLCanvasElement, scale: number): void {
  const w = canvas.width;
  const h = canvas.height;
  const dw = Math.max(1, Math.round(w * scale));
  const dh = Math.max(1, Math.round(h * scale));

  const tmp = document.createElement('canvas');
  tmp.width = dw;
  tmp.height = dh;
  const tctx = tmp.getContext('2d')!;
  tctx.imageSmoothingEnabled = true;
  tctx.drawImage(canvas, 0, 0, w, h, 0, 0, dw, dh);

  const ctx = canvas.getContext('2d')!;
  ctx.imageSmoothingEnabled = true;
  ctx.clearRect(0, 0, w, h);
  ctx.drawImage(tmp, 0, 0, dw, dh, 0, 0, w, h);
}

export interface PrivacyPatchInput {
  imageSrc: string;
  imageNaturalSize: ImageSize;
  imageTransform: ImageTransform;
  stageRect: CropRect;
  mode: PrivacyMode;
}

/** 从原图截取区域并生成马赛克/模糊贴片（JPEG 有损压缩增强抗恢复） */
export async function generatePrivacyPatch(input: PrivacyPatchInput): Promise<string> {
  const img = await loadImageElement(input.imageSrc);
  const src = stageRectToImageRect(input.stageRect, input.imageNaturalSize, input.imageTransform);
  const sw = Math.max(1, Math.round(src.width));
  const sh = Math.max(1, Math.round(src.height));

  const canvas = document.createElement('canvas');
  canvas.width = sw;
  canvas.height = sh;
  const ctx = canvas.getContext('2d')!;
  ctx.drawImage(img, src.x, src.y, sw, sh, 0, 0, sw, sh);

  if (input.mode === 'mosaic') {
    applyMosaicCanvas(canvas, MAX_MOSAIC_BLOCK);
  } else {
    applyHeavyBlurCanvas(canvas, MAX_BLUR_DOWNSCALE);
  }

  return canvas.toDataURL('image/jpeg', 0.82);
}
