import { useEffect, useState } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { aspectToRatio, parseCustomSize } from '@/features/crop/model/crop-service';
import type { CropAspectPreset } from '@/shared/types/editor';
import { haptic } from '@/shared/lib/haptic';

const PRESETS: { id: CropAspectPreset; label: string }[] = [
  { id: 'free', label: '自由' },
  { id: '1:1', label: '1:1' },
  { id: '4:3', label: '4:3' },
  { id: '16:9', label: '16:9' },
  { id: '3:4', label: '3:4' },
];

export function CropToolbar() {
  const activeTool = useEditorStore((s) => s.activeTool);
  const cropAspect = useEditorStore((s) => s.cropAspect);
  const cropCustomSize = useEditorStore((s) => s.cropCustomSize);
  const setCropAspect = useEditorStore((s) => s.setCropAspect);
  const setCropCustomSize = useEditorStore((s) => s.setCropCustomSize);
  const initCropRect = useEditorStore((s) => s.initCropRect);
  const applyCrop = useEditorStore((s) => s.applyCrop);
  const setActiveTool = useEditorStore((s) => s.setActiveTool);
  const pushHistory = useHistoryStore((s) => s.pushHistory);
  const [customInput, setCustomInput] = useState('600x340');
  const [customError, setCustomError] = useState('');

  useEffect(() => {
    if (activeTool !== 'crop') return;
    const canvas = document.querySelector('.editor-canvas');
    if (!canvas) return;
    initCropRect(canvas.clientWidth, canvas.clientHeight);
  }, [activeTool, cropAspect, cropCustomSize, initCropRect]);

  useEffect(() => {
    if (cropCustomSize) {
      setCustomInput(`${cropCustomSize.width}x${cropCustomSize.height}`);
    }
  }, [cropCustomSize]);

  if (activeTool !== 'crop') return null;

  const handleAspect = (preset: CropAspectPreset) => {
    haptic('light');
    setCropAspect(preset);
    setCustomError('');
    const canvas = document.querySelector('.editor-canvas');
    if (canvas) initCropRect(canvas.clientWidth, canvas.clientHeight);
  };

  const handleApplyCustom = () => {
    const parsed = parseCustomSize(customInput);
    if (!parsed) {
      setCustomError('格式如 600x340');
      return;
    }
    setCustomError('');
    haptic('light');
    setCropCustomSize(parsed);
  };

  const handleApply = async () => {
    haptic('medium');
    await applyCrop();
    pushHistory('crop');
  };

  const hint =
    cropAspect === 'custom' && cropCustomSize
      ? `输出 ${cropCustomSize.width}×${cropCustomSize.height}px · 竖图以高为准 / 横图以宽为准`
      : aspectToRatio(cropAspect)
        ? '按长边等比缩放后居中裁切'
        : null;

  return (
    <div className="tool-overlay glass" data-testid="crop-toolbar">
      <div className="tool-overlay__chips">
        {PRESETS.map((p) => (
          <button
            key={p.id}
            type="button"
            className={`measure-chip ${cropAspect === p.id ? 'measure-chip--active' : ''}`}
            onClick={() => handleAspect(p.id)}
          >
            {p.label}
          </button>
        ))}
      </div>

      <div className="crop-custom-input">
        <input
          type="text"
          value={customInput}
          placeholder="600x340"
          aria-label="自定义宽高"
          className={`crop-custom-input__field ${cropAspect === 'custom' ? 'crop-custom-input__field--active' : ''}`}
          onChange={(e) => setCustomInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleApplyCustom()}
        />
        <button type="button" className="btn-accent btn-accent--outline" onClick={handleApplyCustom}>
          应用比例
        </button>
      </div>
      {customError && <p className="crop-custom-input__error">{customError}</p>}

      <div className="tool-overlay__actions">
        <button type="button" className="btn-accent btn-accent--outline" onClick={() => setActiveTool('select')}>
          取消
        </button>
        <button type="button" className="btn-accent" onClick={handleApply}>
          确认裁剪
        </button>
      </div>
      {hint && <p className="tool-overlay__hint">{hint}</p>}
    </div>
  );
}
