import { useRef, useEffect, useCallback, useState } from 'react';
import { Stage, Layer, Image as KonvaImage, Transformer } from 'react-konva';
import type Konva from 'konva';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useGestures } from '@/features/gesture/model/use-gestures';
import { useDrawingTool } from '@/features/drawing/model/use-drawing-tool';
import { ShapeObjects } from '@/widgets/canvas/ui/shape-objects';
import { GuideLinesLayer, CropOverlay, CropTransformer } from '@/widgets/canvas/ui/guide-layers';
import { getPixelRatio } from '@/shared/lib/image-cache';

function useKonvaImage(src: string): HTMLImageElement | undefined {
  const [image, setImage] = useState<HTMLImageElement>();
  useEffect(() => {
    const img = new window.Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => setImage(img);
    img.src = src;
    return () => {
      img.onload = null;
    };
  }, [src]);
  return image;
}

function BackgroundImage() {
  const imageSrc = useEditorStore((s) => s.imageSrc);
  const imageTransform = useEditorStore((s) => s.imageTransform);
  const setImageNaturalSize = useEditorStore((s) => s.setImageNaturalSize);
  const image = useKonvaImage(imageSrc ?? '');

  useEffect(() => {
    if (image) {
      setImageNaturalSize({ width: image.naturalWidth || image.width, height: image.naturalHeight || image.height });
    }
  }, [image, setImageNaturalSize]);

  if (!imageSrc || !image) return null;

  return (
    <KonvaImage
      id="image-main"
      image={image}
      x={imageTransform.x}
      y={imageTransform.y}
      scaleX={imageTransform.scale}
      scaleY={imageTransform.scale}
      rotation={imageTransform.rotation}
      listening={false}
    />
  );
}

export function EditorCanvas() {
  const stageRef = useRef<Konva.Stage>(null);
  const transformerRef = useRef<Konva.Transformer>(null);
  const cropTransformerRef = useRef<Konva.Transformer>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const selectedIds = useEditorStore((s) => s.selectedIds);
  const activeTool = useEditorStore((s) => s.activeTool);
  const toggleToolbar = useEditorStore((s) => s.toggleToolbar);
  const selectObjects = useEditorStore((s) => s.selectObjects);
  const setMagnifierPosition = useEditorStore((s) => s.setMagnifierPosition);

  const { handleTouchStart, handleTouchMove, handleTouchEnd, handleDoubleTap, handleWheel } =
    useGestures(stageRef);
  const { handlePointerDown, handlePointerMove, handlePointerUp } = useDrawingTool(stageRef);

  useEffect(() => {
    const stage = stageRef.current;
    const tr = transformerRef.current;
    if (!stage || !tr || activeTool === 'crop') return;

    const nodes = selectedIds
      .map((id) => stage.findOne(`#${CSS.escape(id)}`))
      .filter(Boolean) as Konva.Node[];
    tr.nodes(nodes);
    tr.getLayer()?.batchDraw();
  }, [selectedIds, activeTool]);

  const handleStageClick = useCallback(
    (e: Konva.KonvaEventObject<MouseEvent | TouchEvent>) => {
      if (activeTool === 'magnifier') {
        const pos = stageRef.current?.getPointerPosition();
        if (pos) setMagnifierPosition(pos);
        return;
      }
      if (activeTool === 'compare' || activeTool === 'crop') return;

      if (e.target === e.target.getStage()) {
        if (activeTool === 'select') {
          selectObjects([]);
          toggleToolbar();
        } else {
          handlePointerDown();
        }
        return;
      }

      if (activeTool === 'select') {
        const id = e.target.id();
        if (id && id !== 'crop-rect') selectObjects([id]);
      }
    },
    [activeTool, handlePointerDown, selectObjects, setMagnifierPosition, toggleToolbar],
  );

  const handleStageDblClick = useCallback(() => {
    if (activeTool === 'select') handleDoubleTap();
  }, [handleDoubleTap, activeTool]);

  useEffect(() => {
    const resize = () => {
      const container = containerRef.current;
      const stage = stageRef.current;
      if (!container || !stage) return;
      stage.width(container.clientWidth);
      stage.height(container.clientHeight);
      stage.batchDraw();
    };
    resize();
    window.addEventListener('resize', resize);
    return () => window.removeEventListener('resize', resize);
  }, []);

  useEffect(() => {
    const onVisibility = () => {
      if (document.hidden) stageRef.current?.cache();
    };
    document.addEventListener('visibilitychange', onVisibility);
    return () => document.removeEventListener('visibilitychange', onVisibility);
  }, []);

  useEffect(() => {
    if (stageRef.current) {
      (window as unknown as { __imgoStage?: Konva.Stage }).__imgoStage = stageRef.current;
    }
  });

  const passiveTools = ['select', 'magnifier', 'compare', 'ocr', 'crop'];
  const isDrawingTool = !passiveTools.includes(activeTool);

  return (
    <div ref={containerRef} className="editor-canvas" data-testid="editor-canvas">
      <Stage
        ref={stageRef}
        width={375}
        height={667}
        pixelRatio={getPixelRatio()}
        onClick={handleStageClick}
        onTap={handleStageClick}
        onDblClick={handleStageDblClick}
        onDblTap={handleStageDblClick}
        onTouchStart={activeTool === 'select' ? handleTouchStart : undefined}
        onTouchMove={activeTool === 'select' ? handleTouchMove : undefined}
        onTouchEnd={activeTool === 'select' ? handleTouchEnd : undefined}
        onWheel={handleWheel}
        onMouseDown={isDrawingTool ? handlePointerDown : undefined}
        onMousemove={isDrawingTool ? handlePointerMove : undefined}
        onMouseup={isDrawingTool ? handlePointerUp : undefined}
      >
        <Layer listening={false} name="background" />
        <Layer name="image" listening={false}>
          <BackgroundImage />
        </Layer>
        <Layer name="shape">
          <ShapeObjects layerFilter="shape" stageRef={stageRef} />
        </Layer>
        <Layer name="text">
          <ShapeObjects layerFilter="text" stageRef={stageRef} />
        </Layer>
        <Layer name="sticker">
          <ShapeObjects layerFilter="sticker" stageRef={stageRef} />
        </Layer>
        <Layer name="guide">
          <GuideLinesLayer />
          <CropOverlay cropTransformerRef={cropTransformerRef} />
        </Layer>
        <Layer name="selection">
          <Transformer
            ref={transformerRef}
            rotateEnabled
            enabledAnchors={['top-left', 'top-right', 'bottom-left', 'bottom-right']}
            anchorSize={12}
            anchorCornerRadius={6}
            borderStroke="#4F8CFF"
            anchorStroke="#4F8CFF"
            anchorFill="#FFFFFF"
            boundBoxFunc={(oldBox, newBox) => {
              if (newBox.width < 8 || newBox.height < 8) return oldBox;
              return newBox;
            }}
          />
          <CropTransformer cropTransformerRef={cropTransformerRef} />
        </Layer>
      </Stage>
    </div>
  );
}
