import type { ImageSize, ImageTransform } from '@/shared/types/editor';

/** 将图片居中适配到舞台 */
export function fitImageToStage(imgSize: ImageSize, stageSize: ImageSize): ImageTransform {
  const scale = Math.min(stageSize.width / imgSize.width, stageSize.height / imgSize.height, 1);
  const dw = imgSize.width * scale;
  const dh = imgSize.height * scale;
  return {
    x: (stageSize.width - dw) / 2,
    y: (stageSize.height - dh) / 2,
    scale,
    rotation: 0,
  };
}

export function readFileAsDataUrl(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

export function loadImageSize(src: string): Promise<ImageSize> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () =>
      resolve({ width: img.naturalWidth || img.width, height: img.naturalHeight || img.height });
    img.onerror = reject;
    img.src = src;
  });
}

const ACCEPT_TYPES = ['image/jpeg', 'image/png', 'image/webp', 'image/gif', 'image/bmp', 'image/heic'];
const MAX_FILE_MB = 50;

export function validateImageFile(file: File): string | null {
  if (!ACCEPT_TYPES.includes(file.type) && !file.type.startsWith('image/')) {
    return '请选择 JPG、PNG、WebP 等图片格式';
  }
  if (file.size > MAX_FILE_MB * 1024 * 1024) {
    return `图片不能超过 ${MAX_FILE_MB}MB`;
  }
  return null;
}

export async function importImageFile(file: File): Promise<{ dataUrl: string; size: ImageSize }> {
  const err = validateImageFile(file);
  if (err) throw new Error(err);
  const dataUrl = await readFileAsDataUrl(file);
  const size = await loadImageSize(dataUrl);
  return { dataUrl, size };
}
