import { useCallback, useRef } from 'react';
import type Konva from 'konva';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { clamp } from '@/shared/lib/math';

interface GestureState {
  lastDist: number;
  lastAngle: number;
  lastCenter: { x: number; y: number };
  velocity: { x: number; y: number };
  lastTime: number;
}

export function useGestures(stageRef: React.RefObject<Konva.Stage | null>) {
  const gestureRef = useRef<GestureState | null>(null);
  const rafRef = useRef<number>(0);
  const imageTransform = useEditorStore((s) => s.imageTransform);
  const setImageTransform = useEditorStore((s) => s.setImageTransform);
  const activeTool = useEditorStore((s) => s.activeTool);

  const applyTransform = useCallback(
    (partial: Partial<typeof imageTransform>) => {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(() => {
        setImageTransform(partial);
      });
    },
    [setImageTransform],
  );

  const getTouchCenter = (touches: TouchList) => {
    let x = 0;
    let y = 0;
    for (let i = 0; i < touches.length; i++) {
      x += touches[i].clientX;
      y += touches[i].clientY;
    }
    return { x: x / touches.length, y: y / touches.length };
  };

  const getTouchDistance = (touches: TouchList) => {
    if (touches.length < 2) return 0;
    const dx = touches[0].clientX - touches[1].clientX;
    const dy = touches[0].clientY - touches[1].clientY;
    return Math.hypot(dx, dy);
  };

  const getTouchAngle = (touches: TouchList) => {
    if (touches.length < 2) return 0;
    return Math.atan2(
      touches[1].clientY - touches[0].clientY,
      touches[1].clientX - touches[0].clientX,
    );
  };

  const handleTouchStart = useCallback(
    (e: Konva.KonvaEventObject<TouchEvent>) => {
      if (activeTool !== 'select') return;
      const touches = e.evt.touches;
      if (touches.length >= 2) {
        e.evt.preventDefault();
        gestureRef.current = {
          lastDist: getTouchDistance(touches),
          lastAngle: getTouchAngle(touches),
          lastCenter: getTouchCenter(touches),
          velocity: { x: 0, y: 0 },
          lastTime: performance.now(),
        };
      }
    },
    [activeTool],
  );

  const handleTouchMove = useCallback(
    (e: Konva.KonvaEventObject<TouchEvent>) => {
      const g = gestureRef.current;
      if (!g) return;
      const touches = e.evt.touches;
      if (touches.length < 2) return;
      e.evt.preventDefault();

      const dist = getTouchDistance(touches);
      const angle = getTouchAngle(touches);
      const center = getTouchCenter(touches);

      const scaleFactor = dist / (g.lastDist || dist);
      const newScale = clamp(imageTransform.scale * scaleFactor, 0.2, 8);
      const deltaAngle = ((angle - g.lastAngle) * 180) / Math.PI;
      const dx = center.x - g.lastCenter.x;
      const dy = center.y - g.lastCenter.y;

      applyTransform({
        scale: newScale,
        rotation: imageTransform.rotation + deltaAngle,
        x: imageTransform.x + dx,
        y: imageTransform.y + dy,
      });

      g.lastDist = dist;
      g.lastAngle = angle;
      g.lastCenter = center;
    },
    [applyTransform, imageTransform],
  );

  const handleTouchEnd = useCallback(() => {
    gestureRef.current = null;
  }, []);

  const handleDoubleTap = useCallback(() => {
    const stage = stageRef.current;
    if (!stage) return;
    const targetScale = imageTransform.scale > 1.5 ? 1 : 2.5;
    applyTransform({ scale: targetScale, x: 0, y: 0 });
    useHistoryStore.getState().pushHistory('double-tap-zoom');
  }, [applyTransform, imageTransform.scale, stageRef]);

  const handleWheel = useCallback(
    (e: Konva.KonvaEventObject<WheelEvent>) => {
      e.evt.preventDefault();
      const delta = e.evt.deltaY > 0 ? 0.95 : 1.05;
      applyTransform({ scale: clamp(imageTransform.scale * delta, 0.2, 8) });
    },
    [applyTransform, imageTransform.scale],
  );

  return {
    handleTouchStart,
    handleTouchMove,
    handleTouchEnd,
    handleDoubleTap,
    handleWheel,
  };
}
