import { useEditorStore } from '@/entities/editor/model/editor-store';
import { haptic } from '@/shared/lib/haptic';

export function MeasureOverlay() {
  const activeTool = useEditorStore((s) => s.activeTool);
  const measureMode = useEditorStore((s) => s.measureMode);
  const setMeasureMode = useEditorStore((s) => s.setMeasureMode);
  const measureResults = useEditorStore((s) => s.measureResults);

  if (activeTool !== 'measure') return null;

  const last = measureResults[measureResults.length - 1];

  return (
    <div className="measure-overlay glass" data-testid="measure-overlay">
      {(['length', 'angle', 'area'] as const).map((mode) => (
        <button
          key={mode}
          type="button"
          className={`measure-chip ${measureMode === mode ? 'measure-chip--active' : ''}`}
          onClick={() => {
            haptic('light');
            setMeasureMode(mode);
          }}
        >
          {{ length: '长度', angle: '角度', area: '面积' }[mode]}
        </button>
      ))}
      {last && (
        <span className="measure-chip measure-chip--active">
          {last.value} {last.unit}
        </span>
      )}
    </div>
  );
}
