import { useCallback, useRef } from 'react';
import type Konva from 'konva';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { distance, angleBetween, polygonArea } from '@/shared/lib/math';
import type { Point } from '@/shared/types/editor';
import { finalizePrivacyPatch } from '@/features/privacy/model/finalize-privacy-patch';
import type { PrivacyMode } from '@/features/privacy/model/privacy-filter';
import { DEFAULT_FONT_SIZE } from '@/shared/config/tools';

export function useDrawingTool(stageRef: React.RefObject<Konva.Stage | null>) {
  const drawingRef = useRef<{ id: string | null; points: number[]; start: Point | null }>({
    id: null,
    points: [],
    start: null,
  });

  const activeTool = useEditorStore((s) => s.activeTool);
  const stroke = useEditorStore((s) => s.stroke);
  const strokeWidth = useEditorStore((s) => s.strokeWidth);
  const addObject = useEditorStore((s) => s.addObject);
  const updateObject = useEditorStore((s) => s.updateObject);
  const selectObjects = useEditorStore((s) => s.selectObjects);
  const setIsDrawing = useEditorStore((s) => s.setIsDrawing);
  const measureMode = useEditorStore((s) => s.measureMode);
  const addMeasureResult = useEditorStore((s) => s.addMeasureResult);
  const nextNumber = useEditorStore((s) => s.nextNumber);
  const pushHistory = useHistoryStore((s) => s.pushHistory);

  const getPointer = useCallback((): Point | null => {
    const stage = stageRef.current;
    if (!stage) return null;
    const pos = stage.getPointerPosition();
    if (!pos) return null;
    const transform = stage.getAbsoluteTransform().copy().invert();
    return transform.point(pos);
  }, [stageRef]);

  const handlePointerDown = useCallback(() => {
    const pos = getPointer();
    if (!pos) return;
    const tool = activeTool;

    if (['pen', 'marker'].includes(tool)) {
      setIsDrawing(true);
      const id = addObject({
        layerId: 'layer-shape',
        type: 'line',
        attrs: {
          points: [pos.x, pos.y],
          stroke: tool === 'marker' ? `${stroke}88` : stroke,
          strokeWidth: tool === 'marker' ? strokeWidth * 2 : strokeWidth,
          lineCap: 'round',
          lineJoin: 'round',
          tension: 0.3,
          globalCompositeOperation: tool === 'marker' ? 'multiply' : 'source-over',
        },
      });
      drawingRef.current = { id, points: [pos.x, pos.y], start: pos };
      return;
    }

    if (['arrow', 'rectangle', 'circle', 'line', 'mosaic', 'blur'].includes(tool)) {
      setIsDrawing(true);
      const isPrivacy = tool === 'mosaic' || tool === 'blur';
      const type =
        tool === 'arrow' ? 'arrow' : tool === 'circle' ? 'ellipse' : isPrivacy ? 'privacy-preview' : tool;
      const id = addObject({
        layerId: isPrivacy ? 'layer-sticker' : 'layer-shape',
        type,
        attrs: {
          x: pos.x,
          y: pos.y,
          width: 0,
          height: 0,
          stroke: isPrivacy ? '#4F8CFF' : stroke,
          strokeWidth: isPrivacy ? 2 : strokeWidth,
          fill: isPrivacy ? 'rgba(79,140,255,0.12)' : 'transparent',
          dash: isPrivacy ? [6, 4] : undefined,
          privacyMode: isPrivacy ? tool : undefined,
          points: tool === 'arrow' || tool === 'line' ? [pos.x, pos.y, pos.x, pos.y] : undefined,
          pointerLength: tool === 'arrow' ? 12 : undefined,
          pointerWidth: tool === 'arrow' ? 12 : undefined,
        },
      });
      drawingRef.current = { id, points: [], start: pos };
      return;
    }

    if (tool === 'text') {
      const id = addObject({
        layerId: 'layer-text',
        type: 'text',
        attrs: {
          x: pos.x,
          y: pos.y,
          text: '极致体验',
          fontSize: DEFAULT_FONT_SIZE,
          fill: stroke,
          draggable: true,
        },
      });
      selectObjects([id]);
      pushHistory('add-text');
      return;
    }

    if (tool === 'number') {
      const n = nextNumber();
      const id = addObject({
        layerId: 'layer-shape',
        type: 'label',
        attrs: {
          x: pos.x,
          y: pos.y,
          text: String(n),
          fontSize: 18,
          fill: '#fff',
          fillShape: stroke,
          cornerRadius: 12,
          padding: 8,
        },
      });
      selectObjects([id]);
      pushHistory('add-number');
      return;
    }

    if (tool === 'watermark') {
      const id = addObject({
        layerId: 'layer-text',
        type: 'watermark',
        attrs: {
          x: pos.x,
          y: pos.y,
          text: 'IMGO',
          fontSize: 32,
          fill: 'rgba(255,255,255,0.35)',
          rotation: -30,
          draggable: true,
        },
      });
      selectObjects([id]);
      pushHistory('add-watermark');
      return;
    }

    if (tool === 'sticker') {
      const id = addObject({
        layerId: 'layer-sticker',
        type: 'text',
        attrs: {
          x: pos.x,
          y: pos.y,
          text: '⭐',
          fontSize: 48,
          draggable: true,
        },
      });
      selectObjects([id]);
      pushHistory('add-sticker');
      return;
    }

    if (tool === 'signature') {
      setIsDrawing(true);
      const id = addObject({
        layerId: 'layer-sticker',
        type: 'line',
        attrs: {
          points: [pos.x, pos.y],
          stroke: '#FFFFFF',
          strokeWidth: 3,
          lineCap: 'round',
          lineJoin: 'round',
          tension: 0.5,
          globalCompositeOperation: 'source-over',
        },
      });
      drawingRef.current = { id, points: [pos.x, pos.y], start: pos };
      return;
    }

    if (tool === 'eyedropper') {
      const canvas = document.querySelector('.editor-canvas canvas') as HTMLCanvasElement | null;
      const stage = stageRef.current;
      if (canvas && stage) {
        const pointer = stage.getPointerPosition();
        if (pointer) {
          const dpr = window.devicePixelRatio || 1;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            const pixel = ctx.getImageData(pointer.x * dpr, pointer.y * dpr, 1, 1).data;
            const hex = `#${[pixel[0], pixel[1], pixel[2]].map((v) => v.toString(16).padStart(2, '0')).join('')}`;
            useEditorStore.getState().setStroke(hex);
          }
        }
      }
      return;
    }

    if (tool === 'measure') {
      setIsDrawing(true);
      drawingRef.current = { id: null, points: [pos.x, pos.y], start: pos };
    }
  }, [
    activeTool,
    addObject,
    getPointer,
    nextNumber,
    pushHistory,
    selectObjects,
    setIsDrawing,
    stroke,
    strokeWidth,
  ]);

  const handlePointerMove = useCallback(() => {
    const pos = getPointer();
    const { id, start } = drawingRef.current;
    if (!pos || !start) return;

    if (id) {
      const tool = activeTool;
      if (['pen', 'marker', 'signature'].includes(tool)) {
        drawingRef.current.points.push(pos.x, pos.y);
        updateObject(id, { points: [...drawingRef.current.points] });
        return;
      }

      if (tool === 'circle') {
        const rx = Math.abs(pos.x - start.x) / 2;
        const ry = Math.abs(pos.y - start.y) / 2;
        updateObject(id, {
          x: Math.min(start.x, pos.x) + rx,
          y: Math.min(start.y, pos.y) + ry,
          radiusX: rx,
          radiusY: ry,
        });
        return;
      }

      if (tool === 'arrow' || tool === 'line') {
        updateObject(id, { points: [start.x, start.y, pos.x, pos.y] });
        return;
      }

      updateObject(id, {
        x: Math.min(start.x, pos.x),
        y: Math.min(start.y, pos.y),
        width: Math.abs(pos.x - start.x),
        height: Math.abs(pos.y - start.y),
      });
      return;
    }

    if (activeTool === 'measure') {
      drawingRef.current.points = [start.x, start.y, pos.x, pos.y];
    }
  }, [activeTool, getPointer, updateObject]);

  const handlePointerUp = useCallback(() => {
    const { id, start } = drawingRef.current;
    setIsDrawing(false);

    if (activeTool === 'measure' && start) {
      const pts = drawingRef.current.points;
      if (pts.length >= 4) {
        const a = { x: pts[0], y: pts[1] };
        const b = { x: pts[2], y: pts[3] };
        if (measureMode === 'length') {
          addMeasureResult({ kind: 'length', value: Math.round(distance(a, b)), unit: 'px', points: [a, b] });
        } else if (measureMode === 'angle') {
          const c = { x: b.x + 50, y: b.y };
          addMeasureResult({
            kind: 'angle',
            value: Math.round(angleBetween(a, b, c)),
            unit: '°',
            points: [a, b, c],
          });
        } else {
          addMeasureResult({
            kind: 'area',
            value: Math.round(polygonArea([a, b, { x: b.x, y: a.y }])),
            unit: 'px²',
            points: [a, b, { x: b.x, y: a.y }],
          });
        }
        addObject({
          layerId: 'layer-shape',
          type: 'measure',
          attrs: {
            points: pts,
            stroke: '#FFD60A',
            strokeWidth: 2,
            dash: [6, 4],
          },
        });
        pushHistory('measure');
      }
    }

    if (id && (activeTool === 'mosaic' || activeTool === 'blur')) {
      const mode = activeTool as PrivacyMode;
      void finalizePrivacyPatch(id, mode).then((ok) => {
        if (ok) pushHistory(`privacy-${mode}`);
      });
      drawingRef.current = { id: null, points: [], start: null };
      return;
    }

    if (id) pushHistory(`draw-${activeTool}`);
    drawingRef.current = { id: null, points: [], start: null };
  }, [activeTool, addMeasureResult, addObject, measureMode, pushHistory, setIsDrawing]);

  return { handlePointerDown, handlePointerMove, handlePointerUp };
}
