import { useMemo } from 'react';
import type Konva from 'konva';
import {
  Arrow,
  Circle,
  Ellipse,
  Label,
  Line,
  Rect,
  Tag,
  Text,
} from 'react-konva';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { useHistoryStore } from '@/entities/history/model/history-store';
import { computeSnap } from '@/features/snap/model/snap-service';
import { PrivacyPatchNode } from '@/features/privacy/ui/privacy-patch-node';
import type { EditorObject } from '@/shared/types/editor';

interface ShapeObjectsProps {
  layerFilter?: 'shape' | 'text' | 'sticker';
  stageRef?: React.RefObject<Konva.Stage | null>;
}

function buildNodeProps(
  obj: EditorObject,
  layers: ReturnType<typeof useEditorStore.getState>['layers'],
  selectObjects: (ids: string[]) => void,
  onDragEnd: (id: string, e: Konva.KonvaEventObject<DragEvent>) => void,
  onDragMove: (id: string, e: Konva.KonvaEventObject<DragEvent>) => void,
) {
  const layer = layers.find((l) => l.id === obj.layerId);
  return {
    id: obj.id,
    key: obj.id,
    draggable: !layer?.locked,
    opacity: layer?.opacity ?? 1,
    onClick: () => selectObjects([obj.id]),
    onTap: () => selectObjects([obj.id]),
    onDragMove: (e: Konva.KonvaEventObject<DragEvent>) => onDragMove(obj.id, e),
    onDragEnd: (e: Konva.KonvaEventObject<DragEvent>) => onDragEnd(obj.id, e),
    ...(obj.attrs as Record<string, unknown>),
  } as Record<string, unknown>;
}

export function ShapeObjects({ layerFilter, stageRef }: ShapeObjectsProps) {
  const objects = useEditorStore((s) => s.objects);
  const layers = useEditorStore((s) => s.layers);
  const selectObjects = useEditorStore((s) => s.selectObjects);
  const snapEnabled = useEditorStore((s) => s.snapEnabled);
  const setGuideLines = useEditorStore((s) => s.setGuideLines);
  const pushHistory = useHistoryStore((s) => s.pushHistory);

  const visibleObjects = useMemo(() => {
    const layerKindMap: Record<string, string> = {
      'layer-shape': 'shape',
      'layer-text': 'text',
      'layer-sticker': 'sticker',
    };
    return objects.filter((obj) => {
      const layer = layers.find((l) => l.id === obj.layerId);
      if (!layer?.visible) return false;
      if (layerFilter && layerKindMap[obj.layerId] !== layerFilter) return false;
      return obj.visible !== false;
    });
  }, [objects, layers, layerFilter]);

  const getNodeSize = (obj: EditorObject) => ({
    width: (obj.attrs.width as number) ?? 40,
    height: (obj.attrs.height as number) ?? 40,
  });

  const handleDragMove = (id: string, e: Konva.KonvaEventObject<DragEvent>) => {
    const stage = stageRef?.current;
    if (!stage || !snapEnabled) return;
    const obj = objects.find((o) => o.id === id);
    if (!obj) return;
    const others = objects
      .filter((o) => o.id !== id)
      .map((o) => ({
        x: (o.attrs.x as number) ?? 0,
        y: (o.attrs.y as number) ?? 0,
        width: (o.attrs.width as number) ?? 40,
        height: (o.attrs.height as number) ?? 40,
      }));
    const size = getNodeSize(obj);
    const { x, y, guides } = computeSnap(
      { x: e.target.x(), y: e.target.y() },
      size,
      { width: stage.width(), height: stage.height() },
      others,
      snapEnabled,
    );
    e.target.x(x);
    e.target.y(y);
    setGuideLines(guides);
  };

  const handleDragEnd = (id: string, e: Konva.KonvaEventObject<DragEvent>) => {
    useEditorStore.getState().updateObject(id, { x: e.target.x(), y: e.target.y() });
    setGuideLines([]);
    pushHistory('move');
  };

  return (
    <>
      {visibleObjects.map((obj) => {
        const props = buildNodeProps(obj, layers, selectObjects, handleDragEnd, handleDragMove);

        switch (obj.type) {
          case 'arrow':
            return <Arrow {...(props as import('konva/lib/shapes/Arrow').ArrowConfig)} />;
          case 'line':
          case 'measure':
            return <Line {...props} />;
          case 'privacy-preview':
            return <Rect {...props} />;
          case 'privacy-patch':
            return <PrivacyPatchNode key={obj.id} obj={obj} common={props} />;
          case 'rect':
          case 'rectangle':
            return <Rect {...props} />;
          case 'circle':
            return <Circle {...props} />;
          case 'ellipse':
            return <Ellipse {...(props as import('konva/lib/shapes/Ellipse').EllipseConfig)} />;
          case 'text':
          case 'watermark':
            return <Text {...props} />;
          case 'label':
            return (
              <Label {...props} x={obj.attrs.x as number} y={obj.attrs.y as number}>
                <Tag fill={(obj.attrs.fillShape as string) ?? '#4F8CFF'} cornerRadius={12} />
                <Text text={obj.attrs.text as string} fill="#fff" padding={8} fontSize={18} />
              </Label>
            );
          default:
            return null;
        }
      })}
    </>
  );
}
