import { useEditorStore } from '@/entities/editor/model/editor-store';
import { haptic } from '@/shared/lib/haptic';
import { ToolIcon } from '@/shared/ui/tool-icon';

export function LayerPanel() {
  const layers = useEditorStore((s) => s.layers);
  const toggleLayerVisibility = useEditorStore((s) => s.toggleLayerVisibility);
  const setLayerOpacity = useEditorStore((s) => s.setLayerOpacity);
  const reorderLayer = useEditorStore((s) => s.reorderLayer);

  const sorted = [...layers].sort((a, b) => b.order - a.order);

  return (
    <div className="layer-panel" data-testid="layer-panel">
      {sorted.map((layer, index) => (
        <div key={layer.id} className="layer-item">
          <button
            type="button"
            className="layer-item__drag"
            aria-label="排序"
            onTouchStart={() => haptic('light')}
          >
            <ToolIcon name="drag" size={16} />
          </button>
          <div className="layer-item__info">
            <span className="layer-item__name">{layer.name}</span>
            <input
              type="range"
              min={0}
              max={100}
              value={Math.round(layer.opacity * 100)}
              className="layer-item__opacity"
              aria-label={`${layer.name} 透明度`}
              onChange={(e) => setLayerOpacity(layer.id, Number(e.target.value) / 100)}
            />
          </div>
          <button
            type="button"
            className="icon-btn icon-btn--sm"
            aria-label={layer.visible ? '隐藏图层' : '显示图层'}
            onClick={() => {
              haptic('light');
              toggleLayerVisibility(layer.id);
            }}
          >
            <ToolIcon name={layer.visible ? 'eye' : 'eye-off'} size={20} />
          </button>
          <button
            type="button"
            className="icon-btn icon-btn--sm"
            aria-label="上移"
            onClick={() => reorderLayer(layer.id, layer.order + 1)}
          >
            <ToolIcon name="up" size={16} />
          </button>
          <button
            type="button"
            className="icon-btn icon-btn--sm"
            aria-label="下移"
            disabled={index === sorted.length - 1}
            onClick={() => reorderLayer(layer.id, Math.max(0, layer.order - 1))}
          >
            <ToolIcon name="down" size={16} />
          </button>
        </div>
      ))}
    </div>
  );
}
