import { create } from 'zustand';
import { immer } from 'zustand/middleware/immer';
import type {
  CropAspectPreset,
  CropRect,
  EditorLayer,
  EditorObject,
  GuideLine,
  ImageSize,
  ImageTransform,
  MeasureResult,
  OcrBlock,
  Point,
  SheetSnap,
  ToolId,
} from '@/shared/types/editor';
import { DEFAULT_STROKE, DEFAULT_STROKE_WIDTH } from '@/shared/config/tools';
import {
  applyCrop as cropImage,
  aspectToRatio,
  computeCropRectForAspect,
  computeCropRectForCustomSize,
  cropToCustomRatio,
} from '@/features/crop/model/crop-service';
import { fitImageToStage } from '@/features/import/model/image-import';
import type { CropCustomSize } from '@/shared/types/editor';

let idCounter = 0;
export const nextId = (prefix = 'obj') => `${prefix}-${++idCounter}-${Date.now()}`;

const defaultLayers: EditorLayer[] = [
  {
    id: 'layer-image',
    name: '图片层',
    kind: 'image',
    visible: true,
    locked: true,
    opacity: 1,
    order: 0,
    nodeIds: ['image-main'],
  },
  {
    id: 'layer-shape',
    name: '形状层',
    kind: 'shape',
    visible: true,
    locked: false,
    opacity: 1,
    order: 1,
    nodeIds: [],
  },
  {
    id: 'layer-text',
    name: '文字层',
    kind: 'text',
    visible: true,
    locked: false,
    opacity: 1,
    order: 2,
    nodeIds: [],
  },
  {
    id: 'layer-sticker',
    name: '贴纸层',
    kind: 'sticker',
    visible: true,
    locked: false,
    opacity: 1,
    order: 3,
    nodeIds: [],
  },
];

export interface EditorState {
  imageSrc: string | null;
  originalImageSrc: string | null;
  imageNaturalSize: ImageSize | null;
  imageTransform: ImageTransform;
  layers: EditorLayer[];
  objects: EditorObject[];
  selectedIds: string[];
  activeTool: ToolId;
  stroke: string;
  strokeWidth: number;
  fill: string;
  opacity: number;
  toolbarVisible: boolean;
  sheetOpen: boolean;
  sheetSnap: SheetSnap;
  sheetTab: 'tools' | 'layers' | 'ocr' | 'export';
  magnifierZoom: number;
  magnifierPosition: Point | null;
  measureMode: 'length' | 'angle' | 'area';
  measureResults: MeasureResult[];
  ocrBlocks: OcrBlock[];
  cropRect: CropRect | null;
  cropAspect: CropAspectPreset;
  cropCustomSize: CropCustomSize | null;
  compareSlider: number;
  guideLines: GuideLine[];
  snapEnabled: boolean;
  isDrawing: boolean;
  numberCounter: number;
}

export interface EditorActions {
  setImageSrc: (src: string) => void;
  loadUploadedImage: (src: string, size: ImageSize, stageSize: ImageSize) => void;
  setActiveTool: (tool: ToolId) => void;
  toggleToolbar: () => void;
  setToolbarVisible: (visible: boolean) => void;
  selectObjects: (ids: string[]) => void;
  addObject: (obj: Omit<EditorObject, 'id'>) => string;
  updateObject: (id: string, attrs: Record<string, unknown>) => void;
  removeObject: (id: string) => void;
  duplicateSelected: () => void;
  setImageTransform: (transform: Partial<ImageTransform>) => void;
  setStroke: (color: string) => void;
  setStrokeWidth: (width: number) => void;
  setOpacity: (opacity: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerOpacity: (layerId: string, opacity: number) => void;
  reorderLayer: (layerId: string, newOrder: number) => void;
  renameLayer: (layerId: string, name: string) => void;
  openSheet: (tab?: EditorState['sheetTab']) => void;
  closeSheet: () => void;
  setSheetSnap: (snap: SheetSnap) => void;
  setMagnifierZoom: (zoom: number) => void;
  setMeasureMode: (mode: EditorState['measureMode']) => void;
  addMeasureResult: (result: MeasureResult) => void;
  setOcrBlocks: (blocks: OcrBlock[]) => void;
  setCropRect: (rect: CropRect | null) => void;
  setCropAspect: (aspect: CropAspectPreset) => void;
  setCropCustomSize: (size: CropCustomSize | null) => void;
  initCropRect: (stageW: number, stageH: number) => void;
  applyCrop: () => Promise<void>;
  setCompareSlider: (value: number) => void;
  setMagnifierPosition: (pos: Point | null) => void;
  setImageNaturalSize: (size: ImageSize) => void;
  setGuideLines: (lines: GuideLine[]) => void;
  setSnapEnabled: (enabled: boolean) => void;
  setIsDrawing: (drawing: boolean) => void;
  nextNumber: () => number;
  loadSnapshot: (objects: EditorObject[], layers: EditorLayer[], transform: ImageTransform) => void;
  reset: () => void;
}

const initialTransform: ImageTransform = { x: 0, y: 0, scale: 1, rotation: 0 };

export const useEditorStore = create<EditorState & EditorActions>()(
  immer((set, get) => ({
    imageSrc: null,
    originalImageSrc: null,
    imageNaturalSize: null,
    imageTransform: { ...initialTransform },
    layers: defaultLayers.map((l) => ({ ...l })),
    objects: [],
    selectedIds: [],
    activeTool: 'select',
    stroke: DEFAULT_STROKE,
    strokeWidth: DEFAULT_STROKE_WIDTH,
    fill: 'transparent',
    opacity: 1,
    toolbarVisible: true,
    sheetOpen: false,
    sheetSnap: 'closed',
    sheetTab: 'tools',
    magnifierZoom: 2,
    magnifierPosition: null,
    measureMode: 'length',
    measureResults: [],
    ocrBlocks: [],
    cropRect: null,
    cropAspect: 'free',
    cropCustomSize: null,
    compareSlider: 0.5,
    guideLines: [],
    snapEnabled: true,
    isDrawing: false,
    numberCounter: 1,

    setImageSrc: (src) =>
      set((s) => {
        s.imageSrc = src;
        if (!s.originalImageSrc) s.originalImageSrc = src;
      }),

    loadUploadedImage: (src, size, stageSize) =>
      set((s) => {
        s.imageSrc = src;
        s.originalImageSrc = src;
        s.imageNaturalSize = size;
        s.imageTransform = fitImageToStage(size, stageSize);
        s.objects = [];
        s.selectedIds = [];
        s.measureResults = [];
        s.ocrBlocks = [];
        s.cropRect = null;
        s.numberCounter = 1;
      }),

    setActiveTool: (tool) =>
      set((s) => {
        s.activeTool = tool;
        if (tool === 'more') {
          s.sheetOpen = true;
          s.sheetTab = 'tools';
          s.sheetSnap = 'half';
        }
        if (tool !== 'crop') s.cropRect = null;
        if (tool !== 'compare') s.compareSlider = 0.5;
        if (tool !== 'magnifier') s.magnifierPosition = null;
      }),

    toggleToolbar: () =>
      set((s) => {
        s.toolbarVisible = !s.toolbarVisible;
      }),

    setToolbarVisible: (visible) =>
      set((s) => {
        s.toolbarVisible = visible;
      }),

    selectObjects: (ids) =>
      set((s) => {
        s.selectedIds = ids;
      }),

    addObject: (obj) => {
      const id = nextId(obj.type);
      set((s) => {
        const layer = s.layers.find((l) => l.id === obj.layerId);
        s.objects.push({ ...obj, id });
        if (layer) layer.nodeIds.push(id);
      });
      return id;
    },

    updateObject: (id, attrs) =>
      set((s) => {
        const obj = s.objects.find((o) => o.id === id);
        if (obj) obj.attrs = { ...obj.attrs, ...attrs };
      }),

    removeObject: (id) =>
      set((s) => {
        s.objects = s.objects.filter((o) => o.id !== id);
        s.layers.forEach((l) => {
          l.nodeIds = l.nodeIds.filter((nid) => nid !== id);
        });
        s.selectedIds = s.selectedIds.filter((sid) => sid !== id);
      }),

    duplicateSelected: () => {
      const { selectedIds, objects } = get();
      selectedIds.forEach((sid) => {
        const src = objects.find((o) => o.id === sid);
        if (!src) return;
        get().addObject({
          layerId: src.layerId,
          type: src.type,
          attrs: {
            ...src.attrs,
            x: ((src.attrs.x as number) ?? 0) + 20,
            y: ((src.attrs.y as number) ?? 0) + 20,
          },
        });
      });
    },

    setImageTransform: (transform) =>
      set((s) => {
        Object.assign(s.imageTransform, transform);
      }),

    setStroke: (color) =>
      set((s) => {
        s.stroke = color;
      }),

    setStrokeWidth: (width) =>
      set((s) => {
        s.strokeWidth = width;
      }),

    setOpacity: (opacity) =>
      set((s) => {
        s.opacity = opacity;
      }),

    toggleLayerVisibility: (layerId) =>
      set((s) => {
        const layer = s.layers.find((l) => l.id === layerId);
        if (layer) layer.visible = !layer.visible;
      }),

    toggleLayerLock: (layerId) =>
      set((s) => {
        const layer = s.layers.find((l) => l.id === layerId);
        if (layer) layer.locked = !layer.locked;
      }),

    setLayerOpacity: (layerId, opacity) =>
      set((s) => {
        const layer = s.layers.find((l) => l.id === layerId);
        if (layer) layer.opacity = opacity;
      }),

    reorderLayer: (layerId, newOrder) =>
      set((s) => {
        const layer = s.layers.find((l) => l.id === layerId);
        if (!layer) return;
        layer.order = newOrder;
        s.layers.sort((a, b) => a.order - b.order);
        s.layers.forEach((l, i) => {
          l.order = i;
        });
      }),

    renameLayer: (layerId, name) =>
      set((s) => {
        const layer = s.layers.find((l) => l.id === layerId);
        if (layer) layer.name = name;
      }),

    openSheet: (tab = 'tools') =>
      set((s) => {
        s.sheetOpen = true;
        s.sheetSnap = 'half';
        s.sheetTab = tab;
      }),

    closeSheet: () =>
      set((s) => {
        s.sheetOpen = false;
        s.sheetSnap = 'closed';
      }),

    setSheetSnap: (snap) =>
      set((s) => {
        s.sheetSnap = snap;
        s.sheetOpen = snap !== 'closed';
      }),

    setMagnifierZoom: (zoom) =>
      set((s) => {
        s.magnifierZoom = zoom;
      }),

    setMeasureMode: (mode) =>
      set((s) => {
        s.measureMode = mode;
      }),

    addMeasureResult: (result) =>
      set((s) => {
        s.measureResults.push(result);
      }),

    setOcrBlocks: (blocks) =>
      set((s) => {
        s.ocrBlocks = blocks;
      }),

    setCropRect: (rect) =>
      set((s) => {
        s.cropRect = rect;
      }),

    setCropAspect: (aspect) =>
      set((s) => {
        s.cropAspect = aspect;
        if (aspect !== 'custom') s.cropCustomSize = null;
      }),

    setCropCustomSize: (size) =>
      set((s) => {
        s.cropCustomSize = size;
        if (size) s.cropAspect = 'custom';
      }),

    initCropRect: (stageW, stageH) =>
      set((s) => {
        if (!s.imageNaturalSize) {
          s.cropRect = { x: stageW * 0.1, y: stageH * 0.1, width: stageW * 0.8, height: stageH * 0.8 };
          return;
        }
        if (s.cropAspect === 'custom' && s.cropCustomSize) {
          s.cropRect = computeCropRectForCustomSize(s.imageNaturalSize, s.cropCustomSize, s.imageTransform);
          return;
        }
        const ratio = aspectToRatio(s.cropAspect);
        if (ratio) {
          s.cropRect = computeCropRectForAspect(
            s.imageNaturalSize,
            { width: stageW, height: stageH },
            ratio,
            s.imageTransform,
          );
        } else {
          const dw = s.imageNaturalSize.width * s.imageTransform.scale;
          const dh = s.imageNaturalSize.height * s.imageTransform.scale;
          s.cropRect = {
            x: s.imageTransform.x + dw * 0.1,
            y: s.imageTransform.y + dh * 0.1,
            width: dw * 0.8,
            height: dh * 0.8,
          };
        }
      }),

    applyCrop: async () => {
      const { imageSrc, cropRect, imageNaturalSize, imageTransform, cropCustomSize, cropAspect } = get();
      if (!imageSrc || !imageNaturalSize) return;

      let result: { dataUrl: string; width: number; height: number };
      if (cropAspect === 'custom' && cropCustomSize) {
        result = await cropToCustomRatio(imageSrc, cropCustomSize.width, cropCustomSize.height);
      } else {
        if (!cropRect) return;
        result = await cropImage(imageSrc, cropRect, imageNaturalSize, imageTransform);
      }

      const canvas = document.querySelector('.editor-canvas');
      const stageSize = {
        width: canvas?.clientWidth ?? 375,
        height: canvas?.clientHeight ?? 667,
      };
      set((s) => {
        s.imageSrc = result.dataUrl;
        s.originalImageSrc = result.dataUrl;
        s.imageNaturalSize = { width: result.width, height: result.height };
        s.imageTransform = fitImageToStage({ width: result.width, height: result.height }, stageSize);
        s.objects = [];
        s.selectedIds = [];
        s.cropRect = null;
        s.cropCustomSize = null;
        s.cropAspect = 'free';
        s.activeTool = 'select';
      });
    },

    setCompareSlider: (value) =>
      set((s) => {
        s.compareSlider = value;
      }),

    setMagnifierPosition: (pos) =>
      set((s) => {
        s.magnifierPosition = pos;
      }),

    setImageNaturalSize: (size) =>
      set((s) => {
        s.imageNaturalSize = size;
      }),

    setGuideLines: (lines) =>
      set((s) => {
        s.guideLines = lines;
      }),

    setSnapEnabled: (enabled) =>
      set((s) => {
        s.snapEnabled = enabled;
      }),

    setIsDrawing: (drawing) =>
      set((s) => {
        s.isDrawing = drawing;
      }),

    nextNumber: () => {
      const n = get().numberCounter;
      set((s) => {
        s.numberCounter += 1;
      });
      return n;
    },

    loadSnapshot: (objects, layers, transform) =>
      set((s) => {
        s.objects = objects.map((o) => ({ ...o, attrs: { ...o.attrs } }));
        s.layers = layers.map((l) => ({ ...l, nodeIds: [...l.nodeIds] }));
        s.imageTransform = { ...transform };
        s.selectedIds = [];
      }),

    reset: () =>
      set((s) => {
        s.objects = [];
        s.selectedIds = [];
        s.imageTransform = { ...initialTransform };
        s.layers = defaultLayers.map((l) => ({ ...l, nodeIds: l.kind === 'image' ? ['image-main'] : [] }));
        s.activeTool = 'select';
        s.numberCounter = 1;
        s.measureResults = [];
        s.ocrBlocks = [];
        s.cropRect = null;
        s.guideLines = [];
        s.magnifierPosition = null;
      }),
  })),
);
