import { useRef, useCallback } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { TOOLS } from '@/shared/config/tools';
import { haptic } from '@/shared/lib/haptic';
import type { ToolId } from '@/shared/types/editor';
import { ToolIcon } from '@/shared/ui/tool-icon';
import { LayerPanel } from '@/widgets/layer-panel/ui/layer-panel';
import { ExportPanel } from '@/features/export/ui/export-panel';
import { OcrPanel } from '@/features/ocr/ui/ocr-panel';

const CATEGORIES = [
  { id: 'common', label: '常用' },
  { id: 'edit', label: '编辑' },
  { id: 'measure', label: '测量' },
  { id: 'recognize', label: '识别' },
] as const;

export function BottomSheet() {
  const sheetOpen = useEditorStore((s) => s.sheetOpen);
  const sheetSnap = useEditorStore((s) => s.sheetSnap);
  const sheetTab = useEditorStore((s) => s.sheetTab);
  const setSheetSnap = useEditorStore((s) => s.setSheetSnap);
  const closeSheet = useEditorStore((s) => s.closeSheet);
  const setActiveTool = useEditorStore((s) => s.setActiveTool);
  const openSheet = useEditorStore((s) => s.openSheet);
  const activeTool = useEditorStore((s) => s.activeTool);

  const dragStartY = useRef(0);
  const dragCurrentY = useRef(0);

  const handleDragStart = useCallback((clientY: number) => {
    dragStartY.current = clientY;
    dragCurrentY.current = clientY;
  }, []);

  const handleDragMove = useCallback(
    (clientY: number) => {
      dragCurrentY.current = clientY;
      const delta = clientY - dragStartY.current;
      if (delta > 120) {
        haptic('light');
        closeSheet();
      } else if (delta < -80) {
        setSheetSnap('full');
      }
    },
    [closeSheet, setSheetSnap],
  );

  if (!sheetOpen) return null;

  const heightClass = sheetSnap === 'full' ? 'bottom-sheet--full' : 'bottom-sheet--half';

  return (
    <>
      <button type="button" className="bottom-sheet__backdrop" aria-label="关闭面板" onClick={closeSheet} />
      <div
        className={`bottom-sheet glass ${heightClass}`}
        data-testid="bottom-sheet"
        role="dialog"
        aria-modal="true"
      >
        <div
          className="bottom-sheet__handle"
          onTouchStart={(e) => handleDragStart(e.touches[0].clientY)}
          onTouchMove={(e) => handleDragMove(e.touches[0].clientY)}
          onMouseDown={(e) => handleDragStart(e.clientY)}
          onMouseMove={(e) => e.buttons === 1 && handleDragMove(e.clientY)}
        />

        <div className="bottom-sheet__tabs">
          {(['tools', 'layers', 'ocr', 'export'] as const).map((tab) => (
            <button
              key={tab}
              type="button"
              className={`bottom-sheet__tab ${sheetTab === tab ? 'bottom-sheet__tab--active' : ''}`}
              onClick={() => openSheet(tab)}
            >
              {{ tools: '工具箱', layers: '图层', ocr: 'OCR', export: '导出' }[tab]}
            </button>
          ))}
        </div>

        <div className="bottom-sheet__content">
          {sheetTab === 'tools' && (
            <>
              {CATEGORIES.map((cat) => (
                <section key={cat.id} className="tool-category">
                  <h3>{cat.label}</h3>
                  <div className="tool-grid">
                    {TOOLS.filter((t) => t.category === cat.id && t.id !== 'more').map((tool) => (
                      <button
                        key={tool.id}
                        type="button"
                        className={`tool-grid__item ${activeTool === tool.id ? 'tool-grid__item--active' : ''}`}
                        onClick={() => {
                          haptic('light');
                          setActiveTool(tool.id as ToolId);
                          closeSheet();
                        }}
                      >
                        <ToolIcon name={tool.icon} size={24} />
                        <span>{tool.label}</span>
                      </button>
                    ))}
                  </div>
                </section>
              ))}
            </>
          )}
          {sheetTab === 'layers' && <LayerPanel />}
          {sheetTab === 'ocr' && <OcrPanel />}
          {sheetTab === 'export' && <ExportPanel />}
        </div>
      </div>
    </>
  );
}
