import { useRef, useEffect, useState } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { haptic } from '@/shared/lib/haptic';

export function CompareSlider() {
  const activeTool = useEditorStore((s) => s.activeTool);
  const compareSlider = useEditorStore((s) => s.compareSlider);
  const setCompareSlider = useEditorStore((s) => s.setCompareSlider);
  const originalImageSrc = useEditorStore((s) => s.originalImageSrc);
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragging, setDragging] = useState(false);

  useEffect(() => {
    if (!dragging) return;
    const onMove = (clientX: number) => {
      const el = containerRef.current?.parentElement;
      if (!el) return;
      const rect = el.getBoundingClientRect();
      const ratio = Math.max(0.05, Math.min(0.95, (clientX - rect.left) / rect.width));
      setCompareSlider(ratio);
    };
    const onMouseMove = (e: MouseEvent) => onMove(e.clientX);
    const onTouchMove = (e: TouchEvent) => onMove(e.touches[0].clientX);
    const onEnd = () => setDragging(false);
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('touchmove', onTouchMove, { passive: true });
    window.addEventListener('mouseup', onEnd);
    window.addEventListener('touchend', onEnd);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchend', onEnd);
    };
  }, [dragging, setCompareSlider]);

  if (activeTool !== 'compare' || !originalImageSrc) return null;

  const pct = compareSlider * 100;

  return (
    <div className="compare-overlay" data-testid="compare-overlay" ref={containerRef}>
      <div
        className="compare-overlay__before"
        style={{
          clipPath: `inset(0 ${100 - pct}% 0 0)`,
          backgroundImage: `url(${originalImageSrc})`,
        }}
      />
      <div
        className="compare-overlay__handle"
        style={{ left: `${pct}%` }}
        onMouseDown={() => {
          haptic('light');
          setDragging(true);
        }}
        onTouchStart={() => {
          haptic('light');
          setDragging(true);
        }}
        role="slider"
        aria-valuenow={Math.round(pct)}
        aria-valuemin={5}
        aria-valuemax={95}
        aria-label="对比滑块"
      >
        <span className="compare-overlay__handle-bar" />
      </div>
      <div className="compare-overlay__labels">
        <span>原图</span>
        <span>当前</span>
      </div>
    </div>
  );
}
