import type { ImageTransform } from '@/shared/types/editor';

function stageToImage(v: number, origin: number, scale: number): number {
  return (v - origin) / scale;
}

/** 将舞台坐标下的 attrs 映射到原图像素坐标 */
export function mapAttrsToImageSpace(
  attrs: Record<string, unknown>,
  transform: ImageTransform,
): Record<string, unknown> {
  const { x: tx, y: ty, scale: s } = transform;
  const mapped: Record<string, unknown> = { ...attrs };

  if (typeof mapped.x === 'number') mapped.x = stageToImage(mapped.x, tx, s);
  if (typeof mapped.y === 'number') mapped.y = stageToImage(mapped.y, ty, s);
  if (typeof mapped.width === 'number') mapped.width = mapped.width / s;
  if (typeof mapped.height === 'number') mapped.height = mapped.height / s;
  if (typeof mapped.radius === 'number') mapped.radius = mapped.radius / s;
  if (typeof mapped.radiusX === 'number') mapped.radiusX = mapped.radiusX / s;
  if (typeof mapped.radiusY === 'number') mapped.radiusY = mapped.radiusY / s;
  if (typeof mapped.fontSize === 'number') mapped.fontSize = mapped.fontSize / s;
  if (typeof mapped.strokeWidth === 'number') mapped.strokeWidth = mapped.strokeWidth / s;

  if (Array.isArray(mapped.points)) {
    const pts = mapped.points as number[];
    const out: number[] = [];
    for (let i = 0; i < pts.length; i += 2) {
      out.push(stageToImage(pts[i], tx, s), stageToImage(pts[i + 1], ty, s));
    }
    mapped.points = out;
  }

  return mapped;
}
