import { useEffect, useState } from 'react';
import { Image as KonvaImage } from 'react-konva';
import type { EditorObject } from '@/shared/types/editor';

interface PrivacyPatchNodeProps {
  obj: EditorObject;
  common: Record<string, unknown>;
}

function usePatchImage(src: string | undefined) {
  const [image, setImage] = useState<HTMLImageElement>();
  useEffect(() => {
    if (!src) return;
    const img = new window.Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => setImage(img);
    img.src = src;
    return () => {
      img.onload = null;
    };
  }, [src]);
  return image;
}

export function PrivacyPatchNode({ obj, common }: PrivacyPatchNodeProps) {
  const patchSrc = obj.attrs.patchSrc as string | undefined;
  const image = usePatchImage(patchSrc);

  if (!image) {
    return null;
  }

  return (
    <KonvaImage
      {...common}
      image={image}
      x={obj.attrs.x as number}
      y={obj.attrs.y as number}
      width={obj.attrs.width as number}
      height={obj.attrs.height as number}
    />
  );
}
