import type { OcrBlock } from '@/shared/types/editor';

let worker: Worker | null = null;

function getWorker(): Worker {
  if (!worker) {
    worker = new Worker(new URL('../workers/ocr.worker.ts', import.meta.url), { type: 'module' });
  }
  return worker;
}

export function recognizeText(imageData: ImageData): Promise<OcrBlock[]> {
  return new Promise((resolve, reject) => {
    const w = getWorker();
    const handler = (e: MessageEvent) => {
      w.removeEventListener('message', handler);
      if (e.data.type === 'result') resolve(e.data.blocks ?? []);
      else reject(new Error(e.data.error ?? 'OCR failed'));
    };
    w.addEventListener('message', handler);
    w.postMessage({ type: 'recognize', imageData });
  });
}

export function terminateOcrWorker(): void {
  worker?.terminate();
  worker = null;
}
