import { useRef } from 'react';
import { useEditorStore } from '@/entities/editor/model/editor-store';
import { importImageFile, loadImageSize } from '@/features/import/model/image-import';
import { DEMO_IMAGE } from '@/shared/config/demo-image';
import { haptic } from '@/shared/lib/haptic';
import { ToolIcon } from '@/shared/ui/tool-icon';

export function ImageUploadButton() {
  const inputRef = useRef<HTMLInputElement>(null);
  const loadUploadedImage = useEditorStore((s) => s.loadUploadedImage);

  const handleFile = async (file: File | undefined) => {
    if (!file) return;
    try {
      haptic('medium');
      const { dataUrl, size } = await importImageFile(file);
      const canvas = document.querySelector('.editor-canvas');
      const stageW = canvas?.clientWidth ?? 375;
      const stageH = canvas?.clientHeight ?? 667;
      loadUploadedImage(dataUrl, size, { width: stageW, height: stageH });
    } catch (e) {
      alert(e instanceof Error ? e.message : '图片加载失败');
    } finally {
      if (inputRef.current) inputRef.current.value = '';
    }
  };

  return (
    <>
      <input
        ref={inputRef}
        type="file"
        accept="image/jpeg,image/png,image/webp,image/gif,image/bmp,image/*"
        className="sr-only"
        aria-hidden
        onChange={(e) => handleFile(e.target.files?.[0])}
      />
      <button
        type="button"
        className="icon-btn"
        aria-label="上传图片"
        data-testid="upload-button"
        onClick={() => {
          haptic('light');
          inputRef.current?.click();
        }}
      >
        <ToolIcon name="upload" />
      </button>
    </>
  );
}

export function ImageUploadOverlay() {
  const imageSrc = useEditorStore((s) => s.imageSrc);
  const loadUploadedImage = useEditorStore((s) => s.loadUploadedImage);
  const inputRef = useRef<HTMLInputElement>(null);

  if (imageSrc) return null;

  const handleFile = async (file: File | undefined) => {
    if (!file) return;
    try {
      const { dataUrl, size } = await importImageFile(file);
      loadUploadedImage(dataUrl, size, { width: window.innerWidth, height: window.innerHeight });
    } catch (e) {
      alert(e instanceof Error ? e.message : '图片加载失败');
    }
  };

  const handleDemo = async () => {
    haptic('light');
    const size = await loadImageSize(DEMO_IMAGE);
    loadUploadedImage(DEMO_IMAGE, size, { width: window.innerWidth, height: window.innerHeight });
  };

  return (
    <div className="upload-overlay glass" data-testid="upload-overlay">
      <input
        ref={inputRef}
        type="file"
        accept="image/jpeg,image/png,image/webp,image/gif,image/bmp,image/*"
        className="sr-only"
        onChange={(e) => handleFile(e.target.files?.[0])}
      />
      <ToolIcon name="upload" size={48} />
      <h2>上传图片开始编辑</h2>
      <p>支持 JPG、PNG、WebP，最大 50MB</p>
      <button type="button" className="btn-accent" onClick={() => inputRef.current?.click()}>
        选择图片
      </button>
      <button type="button" className="btn-accent btn-accent--outline upload-overlay__demo" onClick={handleDemo}>
        试用示例图
      </button>
    </div>
  );
}
